const e={"Wyciskanie sztangi na ławce płaskiej":{steps:["Lie on the bench, eyes under the bar, shoulder blades retracted and pinned to the bench, feet firmly on the floor.","Grip the bar slightly wider than your shoulders, unrack it and position it over your chest.","Lower the bar under control to your lower chest, elbows at about 45 degrees to the torso.","Drive the bar up explosively to full extension without harshly locking out the elbows."],proTip:"Keep your shoulder blades tight and a slight chest arch throughout the movement, this protects the shoulders and increases strength.",targetMuscles:["Chest","Triceps","Front Delts"],primaryMuscle:"chest",equipment:"Olympic Barbell"},"Wyciskanie hantli na ławce płaskiej":{steps:["Sit on the bench with the dumbbells on your thighs, then lie back kicking the dumbbells up over your chest with your knees.","Retract your shoulder blades, set the dumbbells at chest level, palms facing forward.","Lower the dumbbells under control along the sides of your chest, elbows at about 45 degrees.","Press the dumbbells up, bringing them together over the center of your chest without tapping."],proTip:"Greater range of motion than with a barbell, lower a bit deeper to maximally stretch the chest.",targetMuscles:["Chest","Triceps","Front Delts"],primaryMuscle:"chest",equipment:"Dumbbells"},"Wyciskanie hantli (Lekki skos)":{steps:["Set the bench backrest to a 15-30 degree angle.","Lie back with the dumbbells over your upper chest, shoulder blades retracted.","Lower the dumbbells under control to your upper chest, elbows slightly below.","Press the dumbbells up along a slight arc, squeezing the upper chest at the top."],proTip:"A slight incline emphasizes the upper chest without shifting the load onto the shoulders, as a steep angle would.",targetMuscles:["Upper Chest","Triceps","Front Delts"],primaryMuscle:"chest",equipment:"Dumbbells"},"Wyciskanie sztangi na skosie":{steps:["Set the bench to a 30-45 degree angle, lie back with your eyes under the bar.","Retract your shoulder blades, grip the bar slightly wider than your shoulders and unrack it.","Lower the bar under control to your upper chest, just below the collarbones.","Press the bar up along a slightly angled path to full extension."],proTip:"Don't set the angle too steep (max 45 degrees), otherwise the shoulders take over the work instead of the upper chest.",targetMuscles:["Upper Chest","Triceps","Front Delts"],primaryMuscle:"chest",equipment:"Olympic Barbell"},"Rozpiętki hantlami":{steps:["Lie on a flat bench with the dumbbells pressed over your chest, palms facing each other.","Slightly bend your elbows and maintain this angle throughout the movement.","Spread your arms wide out to the sides along an arc until you feel a stretch in the chest.","Bring the dumbbells back together over your chest, squeezing the pecs."],proTip:"Keep your elbows constantly slightly bent, the movement should occur at the shoulder joints, not the elbows.",targetMuscles:["Chest","Front Delts"],primaryMuscle:"chest",equipment:"Dumbbells"},"Rozpiętki na lince (Crossover)":{steps:["Set the cable handles high, grab them and step forward into a slight lunge.","Lean your torso slightly forward, arms spread to the sides with slightly bent elbows.","Pull the handles along an arc down and inward, crossing your hands in front of you.","Slowly return to the stretch, controlling the cable resistance."],proTip:"In the final phase pause for a moment and squeeze the chest hard, the cable provides constant tension throughout the full range.",targetMuscles:["Chest","Front Delts"],primaryMuscle:"chest",equipment:"Cable Machine"},Pompki:{steps:["Get into a front plank position, hands slightly wider than your shoulders, body in a straight line.","Brace your abs and glutes, shoulder blades slightly retracted.","Lower your torso under control, elbows at about 45 degrees to the torso.","Push your body up to full arm extension, keeping your core tight."],proTip:"Don't let your hips sag or pike up, the body should form a straight line from head to heels.",targetMuscles:["Chest","Triceps","Front Delts","Abs"],primaryMuscle:"chest",equipment:"Bodyweight"},"Wyciskanie w maszynie":{steps:["Set the seat height so the handles are at the level of your mid chest.","Sit down, rest your back, retract your shoulder blades and grip the handles.","Push the handles forward to nearly full arm extension.","Return under control, not letting the weight pull your arms too far back."],proTip:"Don't rigidly lock your elbows at the top and don't lift your back off the backrest, keep constant tension on the chest.",targetMuscles:["Chest","Triceps","Front Delts"],primaryMuscle:"chest",equipment:"Machine"},"Wiosłowanie sztangą":{steps:["Stand with feet shoulder-width apart and grab the barbell with an overhand grip slightly wider than your shoulders.","Bend your torso to about 45 degrees, back straight, hips pushed back.","Pull the barbell to your lower abdomen, squeezing your shoulder blades together.","Lower the barbell under control to a full stretch of the back."],proTip:"Keep your back constantly neutral and drive the movement with your elbows, without jerking the weight using torso momentum.",targetMuscles:["Lats","Traps","Rear Delts","Biceps"],primaryMuscle:"back",equipment:"Olympic Barbell"},"Wiosłowanie hantlami na ławce (przodem)":{steps:["Lie face down on an incline bench set at about 30-45 degrees.","Hold the dumbbells hanging freely down, palms facing each other.","Pull the dumbbells to the sides of your torso, squeezing your shoulder blades together.","Lower the dumbbells under control to a full stretch."],proTip:"Bracing against the bench eliminates help from the torso, so all the work falls on the back muscles.",targetMuscles:["Lats","Traps","Rear Delts","Biceps"],primaryMuscle:"back",equipment:"Dumbbells"},"Wiosłowanie hantlem jednorącz (Laty)":{steps:["Rest the knee and hand of one side on the bench, the other foot on the floor.","Grab the dumbbell with your other hand, arm hanging freely down, back straight.","Pull the dumbbell to your hip, keeping your elbow close to the torso and squeezing your shoulder blade.","Lower the dumbbell under control to a full stretch of the lat."],proTip:"Don't rotate your torso to heave the weight up, isolate one side of the back and feel the lat working.",targetMuscles:["Lats","Traps","Rear Delts","Biceps"],primaryMuscle:"back",equipment:"Dumbbells"},"Ściąganie drążka (Szeroki nachwyt)":{steps:["Sit at the cable machine, set the pads on your thighs, grab the bar wide with an overhand grip.","Straighten your torso, slightly arch the chest, pull your shoulder blades down.","Pull the bar to your upper chest, driving your elbows down.","Return under control to full arm extension and stretch."],proTip:"Initiate the movement by pulling your shoulder blades down, not by bending your arms, this engages the lats rather than the biceps.",targetMuscles:["Lats","Teres Major","Biceps","Rear Delts"],primaryMuscle:"back",equipment:"Machine"},"Ściąganie drążka (Wąski nachwyt)":{steps:["Sit at the cable machine, lock your thighs under the pads, grab the handle close (V-grip or narrow overhand).","Straighten your torso, lean the chest slightly back, pull your shoulder blades down.","Pull the handle to your upper chest, keeping your elbows close to the torso.","Return under control to full arm extension."],proTip:"A close grip increases the range of motion and emphasizes the lower part of the lats, work through the full amplitude.",targetMuscles:["Lats","Teres Major","Biceps","Traps"],primaryMuscle:"back",equipment:"Machine"},"Podciąganie na drążku":{steps:["Grab the bar with an overhand grip slightly wider than your shoulders, hang with arms fully extended.","Brace your abs, pull your shoulder blades down, slightly arch the chest.","Pull yourself up, driving your elbows down, until your chin clears the bar.","Lower yourself under control to a full hang."],proTip:"Avoid swinging your body, control especially the negative phase to maximally engage the lats.",targetMuscles:["Lats","Teres Major","Biceps","Abs"],primaryMuscle:"back",equipment:"Pull-up Bar"},"Wiosłowanie na lince siedząc":{steps:["Sit at the low cable, place your feet on the supports, knees slightly bent.","Grab the handle, straighten your back, slightly braced in the lumbar region.","Pull the handle to your abdomen, squeezing your shoulder blades and keeping your elbows close to the torso.","Return under control, letting your shoulder blades spread apart without hunching the back."],proTip:"Don't lean your torso back hard or jerk with momentum, the movement should be driven by the back, not the hips.",targetMuscles:["Lats","Traps","Rear Delts","Biceps"],primaryMuscle:"back",equipment:"Cable Machine"},"Pullover na lince":{steps:["Stand facing the high cable, grab the bar or rope with an overhand grip, arms slightly bent.","Lean your torso slightly forward, brace your abs, set your arms up in front of you.","Pull the bar down in an arc to your thighs, keeping your arms nearly straight.","Return under control to the top, feeling the lats stretch."],proTip:"Maintain a constant, slight bend in the elbows, perform the movement at the shoulders to isolate the lats.",targetMuscles:["Lats","Teres Major","Chest","Triceps"],primaryMuscle:"back",equipment:"Cable Machine"},"Wyciskanie hantli nad głowę (Siedząc)":{steps:["Sit on a bench with an upright backrest, dumbbells at shoulder height, palms facing forward.","Brace your core, keep your back supported, elbows under the dumbbells.","Press the dumbbells overhead to near full arm extension.","Lower the dumbbells under control to shoulder height."],proTip:"Do not overarch your lower back; brace your core and glutes to stabilize your torso.",targetMuscles:["Shoulders","Triceps","Traps"],primaryMuscle:"shoulders",equipment:"Dumbbells"},"Wyciskanie sztangi nad głowę (OHP)":{steps:["Stand with feet hip-width apart, grip the bar slightly wider than your shoulders, bar at collarbone height.","Brace your core and glutes, elbows pointing forward and slightly under the bar.","Press the bar vertically overhead, pulling your head slightly back out of the bar's path.","Once the bar passes your forehead, push your head forward and lock the bar out overhead, then lower under control."],proTip:"Drive the bar in a straight line over the middle of your feet; a braced torso protects the spine from leaning back.",targetMuscles:["Shoulders","Triceps","Traps","Abs"],primaryMuscle:"shoulders",equipment:"Olympic Barbell"},"Wznosy bokiem (Lateral Raise)":{steps:["Stand upright with dumbbells at your sides, palms facing each other, elbows slightly bent.","Brace your core and lean your torso slightly forward.","Raise your arms out to the sides to shoulder height, leading with the elbows slightly above the hands.","Lower the dumbbells under control to your hips."],proTip:"Imagine pouring water from a pitcher (slight pinky-up rotation) to hit the side delt.",targetMuscles:["Side Delts","Traps"],primaryMuscle:"shoulders",equipment:"Dumbbells"},"Wznosy bokiem leżąc (Y-Raise)":{steps:["Lie chest-down on an incline bench set to about 30 degrees.","Hold the dumbbells hanging straight down, thumbs pointing up.","Raise your arms up and slightly out to the sides, forming a Y shape.","Lower the dumbbells under control to the starting position."],proTip:"Use a light weight with thumbs up to target the rear and side delts and the lower traps.",targetMuscles:["Rear Delts","Side Delts","Traps"],primaryMuscle:"shoulders",equipment:"Dumbbells"},"Odwrotne rozpiętki (Tył barku)":{steps:["Sit on the end of a bench or stand in a hip hinge, dumbbells hanging straight down.","Hinge your torso forward, back flat, elbows slightly bent.","Spread your arms wide out to the sides, retracting your shoulder blades and raising the dumbbells to shoulder height.","Lower the dumbbells under control to the starting position."],proTip:"Lead the movement with your elbows, not your hands, and avoid hard scapular retraction to isolate the rear delts.",targetMuscles:["Rear Delts","Traps","Rhomboids"],primaryMuscle:"shoulders",equipment:"Dumbbells"},"Face Pull":{steps:["Set a cable with a rope at face height and grip both ends of the rope with a neutral grip.","Step back with arms extended and lean your torso slightly forward.","Pull the rope toward your face, separating the ends to the sides of your head, elbows high.","Return under control to full arm extension."],proTip:"Keep your elbows high and pull the rope apart at ear level to maximally engage the rear delts and external rotators.",targetMuscles:["Rear Delts","Traps","External Shoulder Rotators"],primaryMuscle:"shoulders",equipment:"Cable Machine"},Arnoldki:{steps:["Sit on a bench with a backrest, dumbbells in front of your shoulders, palms facing you.","As you press the dumbbells up, rotate your wrists so your palms face forward at the top.","Press the dumbbells overhead to near full arm extension.","Lower the dumbbells, rotating your wrists back to the starting position."],proTip:"Smoothly blend the rotation with the press; the rotation works all three heads of the delts.",targetMuscles:["Shoulders","Triceps","Traps"],primaryMuscle:"shoulders",equipment:"Dumbbells"},"Przysiad ze sztangą (High Bar)":{steps:["Place the bar on the upper traps, gripping slightly wider than shoulder width.","Unrack the bar, set your feet shoulder-width apart with toes turned slightly out.","Descend while keeping the torso upright, knees tracking the toes.","Go at least to parallel and drive back up through your heels."],proTip:"In the high-bar variation keep the torso more vertical, which loads the quads harder.",targetMuscles:["Quads","Glutes","Hamstrings","Abs"],primaryMuscle:"quads",equipment:"Olympic Barbell"},"Przysiad ze sztangą (Low Bar)":{steps:["Set the bar lower on the rear delts, with a firm grip and elbows under the bar.","Unrack the bar and set your feet slightly wider, toes turned out.","Push your hips back, leaning the torso further forward as you descend.","Go to parallel and drive back up through your heels, leading with the hips forward."],proTip:"The low-bar variation lets you use heavier weight but requires more torso lean and emphasizes the glutes and hamstrings.",targetMuscles:["Glutes","Hamstrings","Quads","Lower Back"],primaryMuscle:"quads",equipment:"Olympic Barbell"},"Przysiad goblet":{steps:["Hold a dumbbell or kettlebell vertically with both hands at your chest.","Stand with your feet slightly wider than shoulder width, toes turned slightly out.","Descend while keeping the torso upright, elbows between the knees.","Squat deep and drive back up through your heels to standing."],proTip:"Holding the weight in front helps keep the torso vertical, great for learning a deep, clean squat.",targetMuscles:["Quads","Glutes","Abs","Hamstrings"],primaryMuscle:"quads",equipment:"Dumbbells"},"Prasa nożna":{steps:["Sit on the machine, brace your back and hips, and place your feet shoulder-width apart on the platform.","Release the safeties and bend your knees, lowering the platform under control.","Descend to about 90 degrees at the knees without lifting your hips off the backrest.","Drive the platform up through your whole feet without locking the knees rigidly."],proTip:"Don't fully lock out the knees at the top, to keep tension and protect the joints.",targetMuscles:["Quads","Glutes","Hamstrings"],primaryMuscle:"quads",equipment:"Machine"},"Wyprosty nóg na maszynie":{steps:["Sit on the machine, brace your back, and set the pad above your ankles.","Grab the handles and slide your hips into the backrest.","Extend your legs at the knees, raising the pad to full extension.","Lower the pad under control to the starting position."],proTip:"At the top of the extension pause briefly and squeeze the quads, without jerking the lowering phase.",targetMuscles:["Quads"],primaryMuscle:"quads",equipment:"Machine"},"Wykroki chodzone":{steps:["Stand tall with dumbbells at your sides or a barbell on your shoulders, feet hip-width apart.","Step forward and lower your hips, bending both knees to about 90 degrees.","Push off the front leg and step through into a lunge on the other leg.","Continue alternating while keeping the torso upright."],proTip:"Keep the front knee over the ankle rather than pushing it past the toes, and keep the torso vertical.",targetMuscles:["Quads","Glutes","Hamstrings","Abs"],primaryMuscle:"quads",equipment:"Dumbbells"},"Wykroki bułgarskie":{steps:["Stand with your back to a bench, rest the top of one foot on it, dumbbells at your sides.","Place the other (lead) leg forward, with the torso leaning slightly.","Lower your hips down, bending the front knee to about 90 degrees.","Drive back up through the heel of the front leg to extension."],proTip:"Set the front foot far enough out so the knee doesn't push hard past the toes, and you'll engage the glute more.",targetMuscles:["Quads","Glutes","Hamstrings"],primaryMuscle:"quads",equipment:"Dumbbells"},"Martwy Ciąg Rumuński (RDL)":{steps:["Stand holding a barbell with an overhand grip at hip height, feet hip-width apart.","Bend the knees slightly and keep that angle throughout the movement.","Push your hips back, lowering the bar along your legs with a straight back.","Descend until you feel a hamstring stretch, then return by pushing the hips forward."],proTip:"Drive the movement from the hips (hip hinge), not the knees, and keep the bar close to your legs through the full range.",targetMuscles:["Hamstrings","Glutes","Lower Back"],primaryMuscle:"hamstrings",equipment:"Olympic Barbell"},"Martwy ciąg klasyczny":{steps:["Stand right up to the bar, feet hip-width apart, the bar over the midfoot.","Hinge at the hips and knees, grab the bar, back straight, chest up.","Brace your core and pull the bar off the floor, keeping it close to your legs.","Stand up fully, pushing the hips forward, then lower the bar under control."],proTip:"Start the movement by tensing your back and pressing your feet into the floor; the bar should slide along the shins, not travel in an arc.",targetMuscles:["Glutes","Hamstrings","Lower Back","Lats"],primaryMuscle:"hamstrings",equipment:"Olympic Barbell"},"Uginanie nóg na maszynie (Siedząc)":{steps:["Sit on the machine, brace your back, and set the lower pad above your Achilles tendons.","Lower the thigh pad onto your thighs to stabilize your legs.","Bend your knees, pulling the pad under you to maximal contraction.","Return under control to leg extension without locking the knees rigidly."],proTip:"At the end of the curl squeeze the hamstrings hard and control the negative phase, don't let the weight drop freely.",targetMuscles:["Hamstrings","Calves"],primaryMuscle:"hamstrings",equipment:"Machine"},"Uginanie nóg na maszynie (Leżąc)":{steps:["Lie face down on the machine, with the pad set above your Achilles tendons.","Grab the handles, hips pressed into the bench.","Bend your knees, pulling the pad toward your glutes to full contraction.","Lower the pad under control to nearly full leg extension."],proTip:"Don't lift your hips off the bench during the curl, this isolates the hamstrings and protects the lower back.",targetMuscles:["Hamstrings","Calves"],primaryMuscle:"hamstrings",equipment:"Machine"},"Good Morning":{steps:["Set the bar on the upper back as for a squat, feet hip-width apart.","Bend the knees slightly, brace your abs and back.","Push your hips back, leaning the torso forward with a straight back.","Descend until you feel a hamstring stretch, then return by pushing the hips forward."],proTip:"Use a moderate weight and drive the movement from the hips; the back must stay rigid and neutral through the full range.",targetMuscles:["Hamstrings","Glutes","Lower Back"],primaryMuscle:"hamstrings",equipment:"Olympic Barbell"},"Hip Thrust (Wypychanie bioder)":{steps:["Rest your upper back against the bench, barbell across your hips (with a pad), feet on the floor.","Set your feet hip-width apart, heels under your knees.","Drive your hips up, squeezing your glutes, until your torso and thighs are in a straight line.","Lower your hips back to the starting position under control."],proTip:"At the top position, squeeze your glutes hard and tuck your pelvis under to avoid overextending the lower back.",targetMuscles:["Glutes","Hamstrings","Quads"],primaryMuscle:"glutes",equipment:"Olympic Barbell"},"Hip Thrust ze sztangą":{steps:["Rest your upper back against the bench and place the barbell across your hips (use a pad).","Set your feet hip-width apart, heels under your knees.","Brace your glutes and drive your hips up until your torso and thighs are in line.","Pause at the top, then lower your hips under control."],proTip:"At the peak of the movement, squeeze your glutes hard and slightly tuck your pelvis to avoid overextending the lower back.",targetMuscles:["Glutes","Hamstrings","Core"],primaryMuscle:"glutes",equipment:"Olympic Barbell"},"Odwodzenie na lince":{steps:["Attach the cable with an ankle strap to your ankle and stand side-on to the machine.","Hold the frame for stability and shift your weight onto your inner leg.","Abduct the working leg out to the side in a controlled motion.","Slowly return to the starting position without losing tension."],proTip:"Lead the movement with your heel and don't rotate your hips, so you isolate the glute abductors.",targetMuscles:["Gluteus Medius","Gluteus Minimus","Tensor Fasciae Latae"],primaryMuscle:"glutes",equipment:"Cable Machine"},"Glute Bridge":{steps:["Lie on your back, bend your knees, feet flat on the floor.","Arms along your sides, palms down on the floor.","Brace your glutes and lift your hips until your torso is in line with your thighs.","Hold for a second at the top and lower under control."],proTip:"Don't push off with your toes, keep the pressure on your heels to activate your glutes instead of your quads.",targetMuscles:["Glutes","Hamstrings","Core"],primaryMuscle:"glutes",equipment:"Bodyweight"},"Uginanie hantli z supinacją (Ławka skośna)":{steps:["Sit on an incline bench, arms hanging freely down.","Hold the dumbbells with a neutral grip, elbows close to your torso.","Curl the arms while rotating your wrists outward (supination).","Squeeze the biceps at the top and slowly lower, straightening the arm."],proTip:"The stretch on an incline bench maximizes work for the long head of the biceps, so don't cut the range short at the bottom.",targetMuscles:["Biceps","Brachialis","Brachioradialis"],primaryMuscle:"biceps",equipment:"Dumbbells"},"Uginanie sztangi stojąc":{steps:["Stand upright, grip the barbell with an underhand grip at shoulder width.","Press your elbows against your torso, chest out.","Curl the arms, raising the barbell to your shoulders without swinging the torso.","Squeeze the biceps at the top and lower the barbell under control."],proTip:"Keep your elbows fixed against your ribs, moving only at the elbow joint, without using your hips to assist.",targetMuscles:["Biceps","Brachialis","Forearms"],primaryMuscle:"biceps",equipment:"Olympic Barbell"},"Uginanie na lince (Hammer)":{steps:["Attach a rope handle to the low cable pulley.","Stand upright, grip the handle with a neutral grip, elbows by your torso.","Curl the arms, raising the handle to your shoulders.","Squeeze and return under control, keeping constant tension on the cable."],proTip:"Constant cable tension throughout the range strongly engages the brachialis and brachioradialis.",targetMuscles:["Brachioradialis","Biceps","Brachialis"],primaryMuscle:"biceps",equipment:"Cable Machine"},"Uginanie hantli hammer":{steps:["Stand upright with dumbbells in your hands, neutral grip (thumbs up).","Press your elbows against your torso, arms hanging freely down.","Curl the arms, raising the dumbbells without rotating your wrists.","Squeeze at the top and slowly lower to full extension."],proTip:"The hammer grip shifts the load onto the brachioradialis, which is why it thickens the forearm and upper arm.",targetMuscles:["Brachioradialis","Biceps","Brachialis"],primaryMuscle:"biceps",equipment:"Dumbbells"},"Wyprosty francuskie zza głowy":{steps:["Grip a single dumbbell with both hands overhead.","Point your elbows up, close to your head, upper arms vertical.","Lower the weight behind your head, bending only at the elbows.","Extend your arms, tensing the triceps at the top."],proTip:"Keep your elbows narrow and fixed to fully stretch and engage the long head of the triceps.",targetMuscles:["Triceps","Core"],primaryMuscle:"triceps",equipment:"Dumbbells"},"Wyprosty na lince (Pushdown)":{steps:["Attach a bar or rope to the high cable pulley.","Stand upright, press your elbows against your torso.","Extend your arms downward until fully straight.","Squeeze the triceps at the bottom and return under control to a 90-degree bend."],proTip:"Your elbows must stay glued to your sides, any movement away from the body brings in the back muscles and takes work away from the triceps.",targetMuscles:["Triceps","Forearms"],primaryMuscle:"triceps",equipment:"Cable Machine"},"Dips (pompki na poręczach)":{steps:["Grip the parallel bars and lift your body up on straight arms.","Lean your torso slightly forward, legs bent.","Lower your body, bending the elbows to about a 90-degree angle.","Push yourself back up to full arm extension."],proTip:"Keep your torso more upright to emphasize the triceps; a stronger lean shifts the work onto the chest.",targetMuscles:["Triceps","Chest","Front Delts"],primaryMuscle:"triceps",equipment:"Bodyweight"},"Skull Crushers":{steps:["Lie on a flat bench, grip an EZ bar above your chest.","Arms vertical, elbows pointing toward the ceiling.","Lower the weight toward your forehead, bending only at the elbows.","Extend your arms, tensing the triceps, without moving your elbows."],proTip:"Guide the bar behind your head, not just to your forehead, to keep triceps tension in the bottom phase.",targetMuscles:["Triceps","Forearms"],primaryMuscle:"triceps",equipment:"Olympic Barbell"},"Dead Bug (Robak - Brzuch)":{steps:["Lie on your back with your arms extended straight up over your shoulders.","Raise your legs with hips and knees bent at a 90-degree angle.","Press your lower back into the floor and lower the opposite arm and leg.","Return to the starting position and repeat on the other side."],proTip:"Your lower back must stay pressed into the floor at all times; if your back lifts, reduce the range of limb movement.",targetMuscles:["Core","Rectus Abdominis","Transverse Abdominis"],primaryMuscle:"core",equipment:"Bodyweight"},Plank:{steps:["Support yourself on your forearms and toes.","Keep your elbows under your shoulders and your body in a straight line from head to heels.","Brace your abs and glutes; don't raise or drop your hips.","Hold the position for the prescribed time, breathing calmly."],proTip:"Actively tuck your pelvis and squeeze your glutes to avoid lower-back collapse and unload the spine.",targetMuscles:["Core","Rectus Abdominis","Shoulders"],primaryMuscle:"core",equipment:"Bodyweight"},"Ab Rollout":{steps:["Kneel and grip an ab wheel or a loaded barbell.","Brace your abs and keep your back in a neutral position.","Roll the wheel forward, extending your body low over the floor.","Use your ab tension to pull the wheel back to your knees."],proTip:"Only roll out as far as you can keep your abs braced without your lower back collapsing into extension.",targetMuscles:["Rectus Abdominis","Core","Lats"],primaryMuscle:"core",equipment:"Bodyweight"},"Unoszenie nóg w zwisie":{steps:["Hang from the bar with an overhand grip and arms extended.","Brace your abs, lock your shoulders, and don't swing your body.","Raise your legs (straight or bent) toward your chest.","Lower your legs under control without swinging your torso."],proTip:"At the top, tuck your pelvis and lift your hips to engage the lower abs rather than just the hip flexors.",targetMuscles:["Rectus Abdominis","Hip Flexors","Core"],primaryMuscle:"core",equipment:"Pull-up Bar"},"Skręty rosyjskie":{steps:["Sit down, bend your knees, and lean your torso slightly back.","Hold a weight or clasp your hands in front of your chest.","Raise your feet (or keep them on the floor for an easier version).","Rotate your torso to the sides, touching the weight beside your hips."],proTip:"Rotate your whole torso from the spine, not just your arms, to genuinely engage the obliques.",targetMuscles:["Obliques","Rectus Abdominis","Core"],primaryMuscle:"core",equipment:"Dumbbells"},"Modlitewnik (Cable Crunch)":{steps:["Attach a rope to the high pulley and kneel facing the machine.","Grip the rope and hold it by your head or neck.","Crunch your abs, curling your torso down with elbows toward your knees.","Return to the upright position under control, keeping tension on the cable."],proTip:"The movement should come from curling the spine (bringing ribs toward hips), not from lowering your hips.",targetMuscles:["Rectus Abdominis","Obliques","Core"],primaryMuscle:"core",equipment:"Cable Machine"},"Reverse Crunch na ławce":{steps:["Lie on a bench and grip its edge behind your head for stability.","Raise your legs with hips and knees bent at a 90-degree angle.","Using your lower abs, tuck your pelvis and draw your knees in.","Lower your hips under control without abruptly dropping them onto the bench."],proTip:"Focus on tucking the pelvis rather than pulling the knees to maximally activate the lower abs.",targetMuscles:["Rectus Abdominis","Hip Flexors","Core"],primaryMuscle:"core",equipment:"Bodyweight"},"Wspięcia na palce (Nogi proste)":{steps:["Stand on a raised platform on the balls of your feet, heels hanging down.","Keep your legs straight and torso stable, holding on for balance.","Rise up as high as possible onto your toes, contracting the calves.","Slowly lower your heels below the level for a full stretch."],proTip:"Use a full range of motion with a deep stretch at the bottom to fully engage the gastrocnemius.",targetMuscles:["Gastrocnemius","Soleus"],primaryMuscle:"calves",equipment:"Machine"},"Wspięcia na palce siedząc":{steps:["Sit on the machine and rest the pad on the lower part of your thighs above the knees.","Place your feet with the balls on the platform, heels down.","Rise onto your toes, lifting your knees with the pad as high as possible.","Lower your heels below the level in a controlled manner, stretching the calves."],proTip:"The seated version with a bent knee emphasizes the soleus, so perform slow, controlled reps.",targetMuscles:["Soleus","Gastrocnemius"],primaryMuscle:"calves",equipment:"Machine"},"Wyciskanie na maszynie Hammer":{steps:["Sit on the machine, rest your back against the backrest, handles at chest level.","Feet flat on the floor, shoulder blades retracted.","Push the handles forward, straightening your arms without locking the elbows.","Return under control, feeling the chest stretch, without lifting your back."],proTip:"At the top, bring the handles slightly together and squeeze the chest to maximize the muscle contraction.",targetMuscles:["Chest","Triceps","Front Delts"],primaryMuscle:"chest",equipment:"Machine"},"Pec Deck (Butterfly)":{steps:["Sit on the machine, back against the backrest, forearms on the pads.","Elbows at shoulder height, chest pushed out.","Bring your arms together to the front, squeezing the chest in the middle.","Spread your arms under control, feeling the stretch, without jerking."],proTip:"Pause for a second at full contraction and squeeze the chest hard to increase muscle activation.",targetMuscles:["Chest","Front Delts"],primaryMuscle:"chest",equipment:"Machine"},"Otwieranie klatki hantlami":{steps:["Lie on a flat bench with the dumbbells over your chest, palms facing each other.","Slightly bend your elbows and maintain this bend throughout the movement.","Lower the dumbbells in an arc out to the sides until you feel a stretch in the chest.","Bring your arms together in an upward arc, squeezing the chest at the top."],proTip:"Keep a constant slight bend in your elbows, straightening them turns the flye into a press and loads the joints.",targetMuscles:["Chest","Front Delts"],primaryMuscle:"chest",equipment:"Dumbbells"},"Wiosłowanie na maszynie (Hammer)":{steps:["Sit on the machine, brace your chest against the front pad.","Grab the handles, arms extended, shoulder blades relaxed.","Pull the handles toward your torso, squeezing your shoulder blades together.","Return under control, letting your shoulder blades protract forward."],proTip:"Initiate the movement by retracting your shoulder blades, not by jerking with your arms, to focus the work on the back muscles.",targetMuscles:["Lats","Traps","Rhomboids"],primaryMuscle:"back",equipment:"Machine"},"Wiosłowanie T-bar":{steps:["Straddle the T-bar barbell, knees slightly bent, back straight.","Grab the handle, bend your torso forward at the hips.","Pull the weight to your torso, squeezing your shoulder blades together.","Lower the weight under control to a full stretch of the back."],proTip:"Keep your back in a neutral position and your abs braced, don't round the lumbar region under load.",targetMuscles:["Lats","Traps","Rhomboids"],primaryMuscle:"back",equipment:"Olympic Barbell"},"Wiosłowanie Pendleya":{steps:["Stand over the barbell, bend your torso parallel to the floor.","Grab the barbell with an overhand grip wider than your shoulders, back straight.","Explosively pull the barbell to your lower ribs, squeezing your shoulder blades together.","Lower the barbell back to the floor after each rep."],proTip:"Start each rep from a dead weight on the floor and keep your torso still, parallel to the ground.",targetMuscles:["Lats","Rhomboids","Traps"],primaryMuscle:"back",equipment:"Olympic Barbell"},"Podciąganie na drążku podchwytem":{steps:["Grab the bar with an underhand grip at shoulder width, hang.","Brace your abs, pull your shoulder blades down.","Pull yourself up, driving your chest toward the bar.","Lower your body under control to full arm extension."],proTip:"Drive your elbows down and back and squeeze your shoulder blades to engage the back, not just the biceps.",targetMuscles:["Lats","Biceps","Traps"],primaryMuscle:"back",equipment:"Pull-up Bar"},"Ściąganie linki prostymi ramionami":{steps:["Attach a straight bar to the high cable, stand upright.","Grab the bar with an overhand grip, arms almost extended.","Lean your torso slightly forward, pull the bar in an arc to your thighs.","Return under control to the top, feeling the lat stretch."],proTip:"Keep your arms almost straight throughout the movement, bending the elbows shifts the work from the lats to the triceps.",targetMuscles:["Lats","Teres Major","Core"],primaryMuscle:"back",equipment:"Cable Machine"},"Przenoszenie hantla za głowę":{steps:["Lie across a bench, resting only your upper back on it.","Grab a single dumbbell with both hands over your chest, elbows slightly bent.","Lower the dumbbell in an arc behind your head until you feel a stretch.","Pull the dumbbell back over your chest in a controlled arc."],proTip:"The movement should come from the shoulders in a wide arc, maintain a constant slight elbow bend and braced abs.",targetMuscles:["Lats","Chest","Serratus Anterior"],primaryMuscle:"back",equipment:"Dumbbells"},"Szrugi ze sztangą":{steps:["Stand upright, grab the barbell with an overhand grip at shoulder width.","Arms extended, barbell in front of your thighs.","Raise your shoulders straight up toward your ears.","Squeeze the traps at the top and lower your shoulders under control."],proTip:"Move only your shoulders straight up, without rolling them in circles, to safely load the traps.",targetMuscles:["Traps","Levator Scapulae"],primaryMuscle:"back",equipment:"Olympic Barbell"},"Szrugi z hantlami":{steps:["Stand upright with dumbbells in your hands at your sides, neutral grip.","Arms extended, shoulders relaxed down.","Raise your shoulders straight up toward your ears.","Squeeze the traps at the top and slowly lower the dumbbells."],proTip:"Pause for a second at the top and squeeze the traps hard, dumbbells allow a greater range than a barbell.",targetMuscles:["Traps","Levator Scapulae"],primaryMuscle:"back",equipment:"Dumbbells"},"Prostowniki grzbietu (Hyperextensions)":{steps:["Set your hips on the pad of the Roman chair, feet locked.","Cross your arms on your chest or hold a plate for resistance.","Lower your torso down, hinging at the hips with a straight back.","Raise your torso to the line of your legs, contracting the erectors and glutes."],proTip:"Don't hyperextend above the line of your body, stop when your torso is in line with your legs.",targetMuscles:["Lower Back","Glutes","Hamstrings"],primaryMuscle:"back",equipment:"Machine"},"Wyciskanie nad głowę na maszynie":{steps:["Sit on the machine, rest your back against the backrest, handles at shoulder height.","Grip the handles with an overhand grip, elbows under the wrists.","Push the handles vertically overhead without locking out the elbows.","Lower the handles under control back to shoulder height."],proTip:"Keep your core braced and your back against the pad so the load does not shift to your lower back.",targetMuscles:["Front Delts","Side Delts","Triceps"],primaryMuscle:"shoulders",equipment:"Machine"},"Wznosy bokiem na maszynie":{steps:["Sit on the machine and rest your forearms against the side pads.","Keep your torso upright, elbows under the pads.","Raise your arms out to the sides to shoulder height.","Lower your arms under control, not letting the weight drop freely."],proTip:"Lead the movement with your elbows, not your hands, and stop at shoulder height to isolate the side delt.",targetMuscles:["Side Delts","Traps"],primaryMuscle:"shoulders",equipment:"Machine"},"Wznosy bokiem na wyciągu":{steps:["Stand side-on to a low cable and grip the handle with the hand nearest the machine.","Keep the working arm in front of your body, the other hand holding the frame.","Raise your arm out to the side to shoulder height, elbow slightly bent.","Lower your arm under control, maintaining constant cable tension."],proTip:"The constant cable tension keeps the shoulder working even at the bottom of the movement, which a free weight does not.",targetMuscles:["Side Delts","Rear Delts"],primaryMuscle:"shoulders",equipment:"Cable Machine"},"Wznosy bokiem na lince (zza pleców)":{steps:["Stand side-on to a low cable, running the cable behind your back.","Grip the handle with the hand farther from the machine, arm by your hip.","Raise your arm out to the side and slightly back to shoulder height.","Lower your arm under control, feeling the tension in the side delt."],proTip:"Running the cable behind your back changes the line of pull and more strongly emphasizes the side and rear delts.",targetMuscles:["Side Delts","Rear Delts","Traps"],primaryMuscle:"shoulders",equipment:"Cable Machine"},"Rotacje ramienia z gumą frontem":{steps:["Stand facing a band anchored at elbow height, grab the band and pull your elbow to your torso at a 90-degree angle.","Keeping your elbow at your side, rotate your forearm outward, away from your body's midline.","Pause at peak tension, feeling the work in the back of the shoulder.","Return under control to the starting position, not letting the band jerk your arm."],proTip:"Hold a rolled towel between your elbow and torso to force the rotator cuff to work instead of letting the deltoid assist.",targetMuscles:["Rotator Cuff Muscles","Infraspinatus","Rear Delts"],primaryMuscle:"shoulders",equipment:"Resistance Band"},"Aniołki i demony":{steps:["Lie chest-down with your arms extended overhead in a Y shape.","Lift your chest and arms, sweeping your hands along an arc down to your hips (angel), retracting your shoulder blades.","Reverse the motion, sweeping your arms back along the same arc overhead (demon), keeping them off the floor throughout.","Perform the movement smoothly and under control, maintaining tension in your upper back."],proTip:"Point your thumbs toward the ceiling throughout the range to maximize external rotation and lower trap work.",targetMuscles:["Traps","Rhomboids","Rear Delts"],primaryMuscle:"back",equipment:"Bodyweight"},"Wall Angel":{steps:["Stand with your back to the wall, touching it with your head, upper back, and glutes, feet slightly forward.","Rest your forearms and the backs of your hands against the wall, elbows bent to 90 degrees.","Slide your arms up the wall to full extension without lifting your wrists or elbows off the wall.","Return under control, pulling your shoulder blades down and together."],proTip:"Keep your lower ribs tucked and your lower back close to the wall so the movement comes from the shoulder blades, not the lumbar spine.",targetMuscles:["Lower Traps","Rhomboids","Rotator Cuff Muscles"],primaryMuscle:"back",equipment:"Bodyweight"},"Rozciąganie gumy nad głową":{steps:["Grip the band with both hands wider than shoulder-width, arms extended overhead.","Stretch the band out to the sides, lowering your straight arms along an arc behind your head.","Go as low as your shoulder mobility allows, keeping your arms straight.","Return overhead under control, keeping tension on the band throughout."],proTip:"The narrower your grip, the greater the shoulder stretch; set your hand spacing so you do not compensate by arching your back.",targetMuscles:["Shoulders","Chest","Rotator Cuff Muscles"],primaryMuscle:"shoulders",equipment:"Resistance Band"},"Hack Squat (maszyna)":{steps:["Step onto the machine's platform, rest your back and shoulders against the pads, feet hip-width apart.","Release the safeties and descend under control, bending the knees to about 90 degrees or lower.","Keep your back flat against the pad and your heels pressed into the platform.","Drive the weight up through your heels back to extension without fully locking the knees."],proTip:"Set your feet higher on the platform to engage the glutes and hamstrings more, or lower to shift the emphasis to the quads.",targetMuscles:["Quads","Glutes","Hamstrings"],primaryMuscle:"quads",equipment:"Machine"},"Wyciskanie jednonóż na suwnicy":{steps:["Sit in the Smith machine and set one foot in the middle of the platform, moving the other leg off the platform.","Release the safeties and lower the weight, bending the working leg's knee to about 90 degrees.","Make sure the knee tracks the toes and doesn't cave inward.","Drive the platform through your heel to nearly full extension without locking the knee."],proTip:"Set your foot centrally on the platform to avoid overloading the knee, and keep the hip stable without rotating the pelvis.",targetMuscles:["Quads","Glutes","Hamstrings"],primaryMuscle:"quads",equipment:"Smith Machine"},"Sissy Squat":{steps:["Stand upright, holding a stable point with one hand for balance, feet hip-width apart.","Raise your heels and simultaneously lean the torso back, driving the knees forward.","Lower yourself until the torso and thighs form a single line, keeping the hips extended.","Squeeze the quads and return under control to upright, straightening the knees."],proTip:"Keep a straight line from the knees through the hips to the shoulders, don't bend at the hips, to maximally stretch the quads.",targetMuscles:["Quads","Abs","Hip Flexors"],primaryMuscle:"quads",equipment:"Bodyweight"},"Przywodziciele na maszynie":{steps:["Sit on the machine, brace your back, and place your thighs on the outside of the pads, knees spread out to the sides.","Grab the handles and stabilize your torso against the backrest.","Squeeze your thighs together against the resistance until the pads nearly touch.","Return under control to the spread position, feeling the stretch on the inner thighs."],proTip:"Don't bounce at the end of the stretch; hold the tension briefly when the thighs come together to better engage the adductors.",targetMuscles:["Adductors","Gracilis"],primaryMuscle:"quads",equipment:"Machine"},"Cossack Squat":{steps:["Stand in a wide stance with your toes turned slightly out.","Shift your weight onto one leg, bending its knee deeply while the other leg stays straight.","Descend low, keeping the working leg's heel on the ground and the torso upright.","Drive back up through the heel to the stance and repeat on the other side."],proTip:"Let the toes of the straight leg lift up to increase the adductor stretch and maintain balance.",targetMuscles:["Quads","Glutes","Adductors"],primaryMuscle:"quads",equipment:"Bodyweight"},"Przysiady wykroczne":{steps:["Stand tall and step forward with one leg to a lunge length.","Lower your hips down, bending both knees to about 90 degrees, the rear knee close to the floor.","Keep the torso upright and the front knee over the line of the foot.","Push off the front heel and return to standing, switching legs."],proTip:"Take a long enough step so the front shin stays vertical, which takes load off the knee joint.",targetMuscles:["Quads","Glutes","Hamstrings"],primaryMuscle:"quads",equipment:"Bodyweight"},"Zakroki sprinterskie":{steps:["Stand tall and shift your weight onto one leg.","Step back with the other leg, lowering your hips until the rear knee nears the floor.","Keep the torso leaning slightly forward, as in a sprinter's stance, the front shin vertical.","Dynamically push off the front leg and return to the start, driving the rear-leg knee up."],proTip:"Strongly emphasize the push-off and knee-drive phase to activate the glutes and mimic the running motion.",targetMuscles:["Glutes","Quads","Hamstrings"],primaryMuscle:"glutes",equipment:"Bodyweight"},"Wejścia bokiem na skrzynię":{steps:["Stand sideways to the box and place the whole foot of the near leg on it.","Drive through the heel of the leg on the box, stepping up and extending the hip.","Stand tall on the box, controlling the position of the other leg.","Lower yourself under control back to the floor and repeat, without pushing off with the lower leg."],proTip:"All the drive should come from the leg on the box, don't push off with the lower leg, to maximally load the working leg's glute.",targetMuscles:["Glutes","Quads","Hip Abductors"],primaryMuscle:"glutes",equipment:"Bodyweight"},"Odwodziciele na maszynie":{steps:["Sit on the machine, position your thighs against the inside of the pads, knees together.","Grab the handles and stabilize your back against the backrest.","Spread your thighs outward against the resistance until full abduction.","Return under control until your knees come together, without letting the weight jerk your legs."],proTip:"A slight forward lean of your torso engages the upper portion of the gluteus maximus more.",targetMuscles:["Gluteus Medius","Gluteus Maximus","Tensor Fasciae Latae"],primaryMuscle:"glutes",equipment:"Machine"},"Glute Kickback na wyciągu":{steps:["Attach the cable with an ankle strap to your ankle, stand facing the low cable, and hold the frame.","Lean your torso slightly forward and stabilize your hips.","Push your leg back in an arc, extending the hip and squeezing your glute at the top.","Return forward under control, without letting the weight pull your leg too far."],proTip:"The peak of the movement comes from hip extension, not from arching the lower back; pause briefly and squeeze your glute.",targetMuscles:["Glutes","Hamstrings"],primaryMuscle:"glutes",equipment:"Cable Machine"},"Pull Through":{steps:["Stand facing away from the low cable, pass the rope handle between your legs, and grab it with both hands.","Step forward, feet shoulder-width apart, knees slightly bent.","Push your hips back (hip hinge), letting the cable pull your hands back between your legs.","Drive your hips forward, standing up and squeezing your glutes at the end of the movement."],proTip:"This is a hip hinge, not a squat; your arms are just a hook, all the work comes from hip extension.",targetMuscles:["Glutes","Hamstrings","Lower Back"],primaryMuscle:"glutes",equipment:"Cable Machine"},"Wyprosty biodra z gumą":{steps:["Anchor the band low and loop it around one ankle, standing facing the anchor point.","Hold onto a stable point and stabilize your torso.","Push the loaded leg back, extending your hip and squeezing your glute.","Return forward under control, keeping tension on the band through the full range."],proTip:"Keep your torso upright and don't arch your lower back; the movement should come solely from hip extension.",targetMuscles:["Glutes","Hamstrings"],primaryMuscle:"glutes",equipment:"Resistance Band"},"Uginanie na modlitewniku (Preacher)":{steps:["Sit at the preacher bench, rest the backs of your upper arms flat against the pad.","Grip the weight (a dumbbell or handle) with your arms almost fully extended.","Curl the forearm, pulling the weight toward your shoulder while keeping your elbows on the pad.","Lower under control to near-full extension, without locking the joint."],proTip:"Don't snap your arm to full extension, to protect the biceps tendon stop just short of full lockout.",targetMuscles:["Biceps","Brachialis","Brachioradialis"],primaryMuscle:"biceps",equipment:"Machine"},"Uginania ze sztangą na modlitewniku":{steps:["Sit at the preacher bench, rest your upper arms flat against the pad, grip the barbell with an underhand grip.","Extend your arms almost fully, keeping your elbows on the pad.","Curl the forearms, pulling the barbell toward your shoulders with full biceps tension.","Lower the barbell under control to near-full extension, without bouncing at the bottom."],proTip:"Keep your elbows and shoulders pressed against the pad throughout the movement to eliminate help from the shoulder girdle.",targetMuscles:["Biceps","Brachialis","Brachioradialis"],primaryMuscle:"biceps",equipment:"Olympic Barbell"},"Uginania łokci z hantlami stojąc":{steps:["Stand upright, dumbbells in your hands along your torso, neutral or underhand grip.","Keeping your elbows by your torso, curl your forearms, raising the dumbbells to your shoulders.","At the top of the movement tense the biceps, optionally supinating the wrists.","Lower the dumbbells under control to full arm extension."],proTip:"Don't swing the torso; if you have to throw the weight with your hips, pick lighter dumbbells and isolate the biceps.",targetMuscles:["Biceps","Brachialis","Brachioradialis"],primaryMuscle:"biceps",equipment:"Dumbbells"},"Uginanie na wyciągu dolnym":{steps:["Stand facing the low cable pulley, grip the bar or handle with an underhand grip.","Keep your elbows by your torso, arms almost fully extended.","Curl your forearms, pulling the handle toward your shoulders with full biceps tension.","Lower under control to extension, maintaining constant cable tension."],proTip:"The cable maintains tension in every phase, so don't let the weight drop freely in the negative phase.",targetMuscles:["Biceps","Brachialis","Brachioradialis"],primaryMuscle:"biceps",equipment:"Cable Machine"},"Uginanie na maszynie":{steps:["Sit on the machine, rest the backs of your upper arms against the pad, grip the handles with an underhand grip.","Adjust the seat so your elbows align with the machine's axis of rotation.","Curl your forearms, pulling the handles with full biceps tension.","Return under control to near-full extension, without locking the joints."],proTip:"The machine stabilizes your arms, so focus on full tension at the top and a slow eccentric phase.",targetMuscles:["Biceps","Brachialis"],primaryMuscle:"biceps",equipment:"Machine"},"Wyciskanie wąsko (Close-grip)":{steps:["Lie on the bench, grip the barbell slightly narrower than shoulder width.","Unrack the barbell and position it over your chest with arms extended.","Lower the barbell to your lower chest, keeping your elbows close to your torso.","Press the barbell to extension, tensing the triceps at the top."],proTip:"Don't narrow the grip too much; a shoulder-width hand spacing protects the wrists and still strongly engages the triceps.",targetMuscles:["Triceps","Chest","Front Delts"],primaryMuscle:"triceps",equipment:"Olympic Barbell"},"Francuskie wyciskanie sztangi leżąc":{steps:["Lie on the bench, grip the barbell (preferably an EZ bar) at shoulder width, arms extended over your chest.","Keeping your elbows fixed, bend your forearms, lowering the barbell to your forehead or behind your head.","Stop just above your forehead, feeling the stretch in the triceps.","Extend your arms, pressing the barbell back over your chest."],proTip:"Keep your elbows fixed and pointed slightly back to maximally stretch the long head of the triceps.",targetMuscles:["Triceps"],primaryMuscle:"triceps",equipment:"Olympic Barbell"},"Wyciskanie hantla oburącz w klęku":{steps:["Kneel or sit upright, grip a single dumbbell with both hands by the top plate.","Raise the dumbbell overhead with arms extended.","Bending your elbows, lower the dumbbell behind your head under control, elbows pointing up.","Extend your arms, pressing the dumbbell back overhead."],proTip:"Keep your elbows close to your head and pointing forward to isolate the triceps instead of spreading the movement to the shoulders.",targetMuscles:["Triceps","Abs"],primaryMuscle:"triceps",equipment:"Dumbbells"},"Triceps na maszynie":{steps:["Sit on the machine, rest your back and align your arms with the axis of rotation.","Grip the handles, elbows bent.","Extend your arms, pressing the handles with full triceps tension.","Return under control to the bent position, without letting the weight drop freely."],proTip:"Full extension with a brief squeeze at the end maximizes the triceps contraction; don't jerk the return phase.",targetMuscles:["Triceps"],primaryMuscle:"triceps",equipment:"Machine"},"Kickback z hantlą":{steps:["Bend your torso forward, brace one hand on a bench, hold a dumbbell in the other.","Raise your upper arm to torso height, pressed against your side, forearm hanging down.","Extend your forearm back until the whole arm is straight and parallel to the floor.","Tense the triceps at the top and return under control to the bent position."],proTip:"The elbow must stay fixed and high, only the forearm moves; pause briefly at full extension.",targetMuscles:["Triceps","Rear Delts"],primaryMuscle:"triceps",equipment:"Dumbbells"},"Brzuszki na maszynie":{steps:["Sit on the machine, rest your back, and grip the handles or place your chest against the pads.","Set the load and stabilize your hips on the seat.","Crunch your abs, flexing your torso forward through the thoracic spine.","Return under control to the starting position without fully releasing the tension."],proTip:"The movement should come from curling the spine through the abs, not from pulling the handles with your arms.",targetMuscles:["Rectus Abdominis","Obliques"],primaryMuscle:"core",equipment:"Machine"},"Pallof Press":{steps:["Stand sideways to the cable at chest height and grip the handle with both hands at your sternum.","Set your feet shoulder-width apart, slightly bend your knees, and brace your abs.","Press your arms straight out in front of you, resisting the rotation the cable forces.","Hold the extended position briefly, then return the handle to your chest under control."],proTip:"The farther you stand from the machine, the greater the rotational force; pick a distance where your torso never rotates.",targetMuscles:["Obliques","Rectus Abdominis","Core"],primaryMuscle:"core",equipment:"Cable Machine"},"Cable Woodchopper":{steps:["Set the cable high, stand sideways, and grip the handle with both hands above one shoulder.","Set your feet shoulder-width apart and brace your abs.","Pull the handle diagonally down to the opposite hip, rotating your torso and hips.","Return along the same path under control and repeat, then switch sides."],proTip:"The rotation should come from the torso and hips while your arms stay extended; don't drive the movement with your arms alone.",targetMuscles:["Obliques","Rectus Abdominis","Glutes"],primaryMuscle:"core",equipment:"Cable Machine"},"Mountain Climbers":{steps:["Get into a front plank position with hands under your shoulders and body in a straight line.","Brace your abs and drive one knee dynamically toward your chest.","Quickly switch legs, driving the other knee in and extending the first.","Continue alternating at an even pace, keeping your hips low."],proTip:"Don't raise your hips up; keep a flat back and a stable torso so the work comes from the abs, not from rocking.",targetMuscles:["Rectus Abdominis","Obliques","Hip Flexors"],primaryMuscle:"core",equipment:"Bodyweight"},"Hollow Hold":{steps:["Lie on your back with your arms extended overhead and your legs straight.","Press your lower back into the floor while bracing your abs.","Simultaneously raise your shoulders and legs off the floor, forming a boat shape.","Hold the tension and position for the set time, breathing calmly."],proTip:"Your lower back must touch the floor the whole time; if it lifts, raise your legs higher to keep the abs braced.",targetMuscles:["Rectus Abdominis","Core","Hip Flexors"],primaryMuscle:"core",equipment:"Bodyweight"},"Wspięcia na palce na suwnicy":{steps:["Position your shoulders under the Smith machine bar, stand with the balls of your feet on a raised platform, heels in the air.","Unrack the bar from the hooks and stabilize your torso.","Lower your heels as far down as possible, stretching the calves.","Rise up as high as possible onto your toes, contracting the calves at the top, and return in a controlled manner."],proTip:"Use a full range of motion from a deep stretch to a maximum rise, with a short pause at the top.",targetMuscles:["Gastrocnemius","Soleus"],primaryMuscle:"calves",equipment:"Smith Machine"},"Wspięcia na maszynie stojąc":{steps:["Step under the pads of the standing calf machine, balls of your feet on the platform, heels in the air.","Stand up so the pads rest on your shoulders, torso stable.","Lower your heels down, feeling a full stretch in the calves.","Rise up onto your toes as far as possible, contracting the calves, and return down in a controlled manner."],proTip:"Don't shorten the range or bounce at the bottom, a controlled eccentric phase builds the calves best.",targetMuscles:["Gastrocnemius","Soleus"],primaryMuscle:"calves",equipment:"Machine"},"Donkey Calf Raise":{steps:["Bend your torso forward at the hips, resting your hands on a stable support, balls of your feet on the platform.","Place the load low on your hips (machine or partner), heels hanging off the platform.","Lower your heels down, stretching the calves to the maximum.","Rise onto your toes as high as possible, contracting the calves at the top, and return in a controlled manner."],proTip:"The forward lean stretches the calves in a lengthened position, keep your knees slightly bent and still throughout the movement.",targetMuscles:["Gastrocnemius","Soleus"],primaryMuscle:"calves",equipment:"Machine"},"Wyciskanie sztangi na ławce ujemnej (deklina)":{steps:["Lie on a decline bench and lock your legs under the pads.","Grip the bar slightly wider than shoulders and unrack it.","Lower the bar under control to your lower chest.","Press the bar up while squeezing the lower chest."],proTip:"Keep elbows at ~45 degrees to maximize lower chest activation and protect the shoulders.",targetMuscles:["Lower chest","Triceps","Front delts"],primaryMuscle:"chest",equipment:"Barbell"},"Wyciskanie hantli na ławce ujemnej (deklina)":{steps:["Set the bench to a decline angle and secure your legs under the pads.","Lie back holding dumbbells over your chest, palms facing in or forward.","Lower the dumbbells to the sides down to lower chest level.","Press the dumbbells up and squeeze the chest at the top."],proTip:"Greater range than the barbell: let the dumbbells sink deeper for a better stretch.",targetMuscles:["Lower chest","Triceps","Front delts"],primaryMuscle:"chest",equipment:"Dumbbells"},"Wyciskanie na Smith maszynie (ławka skośna)":{steps:["Position the incline bench so the Smith bar descends to your upper chest.","Grip the bar slightly wider than shoulders and rotate to unlock it.","Lower the bar under control to your upper chest.","Press the bar up along the track without locking the elbows."],proTip:"The fixed path lets you safely overload the upper chest even without a spotter.",targetMuscles:["Upper chest","Front delts","Triceps"],primaryMuscle:"chest",equipment:"Smith Machine"},"Wyciskanie na Smith maszynie (ławka płaska)":{steps:["Center a flat bench under the Smith machine bar.","Lie so the bar descends to mid-chest, grip slightly wider than shoulders.","Unlock the bar and lower it under control to your chest.","Press the bar up along the track, squeezing the chest."],proTip:"Great for training to failure: the safety hooks replace a spotter.",targetMuscles:["Chest","Triceps","Front delts"],primaryMuscle:"chest",equipment:"Smith Machine"},"Wyciskanie na maszynie Hammer (skos góra)":{steps:["Sit in the incline Hammer Strength machine with your back against the pad.","Grab the handles at upper chest height.","Drive your arms up and forward along the machine arc.","Return under control to a stretch without lifting your shoulder blades."],proTip:"Work one arm at a time to even out side-to-side imbalances.",targetMuscles:["Upper chest","Front delts","Triceps"],primaryMuscle:"chest",equipment:"Hammer Strength Machine"},"Wyciskanie na maszynie Hammer (skos dół)":{steps:["Sit in the decline Hammer Strength machine with handles below shoulder level.","Grab the handles at lower chest height with shoulder blades retracted.","Drive your arms down and forward along the machine arc.","Return under control to a full stretch of the lower chest."],proTip:"Focus on squeezing the lower chest at the end of the rep with a short pause.",targetMuscles:["Lower chest","Triceps","Front delts"],primaryMuscle:"chest",equipment:"Hammer Strength Machine"},"Dipy na poręczach (na klatkę)":{steps:["Grab the parallel bars and support yourself on straight arms.","Lean your torso forward and flare the elbows slightly out.","Lower your body until shoulders drop just below the elbows.","Press back up while keeping the forward torso lean."],proTip:"Leaning the torso forward shifts work from the triceps to the lower chest.",targetMuscles:["Lower chest","Triceps","Front delts"],primaryMuscle:"chest",equipment:"Bodyweight"},"Dipy z obciążeniem (na klatkę)":{steps:["Attach a dip belt with weight and get onto the bars on straight arms.","Lean your torso forward to emphasize the chest.","Lower your body under control until the chest is stretched.","Press back up without fully locking the elbows."],proTip:"Add weight only once you can do 12+ clean reps with bodyweight.",targetMuscles:["Lower chest","Triceps","Front delts"],primaryMuscle:"chest",equipment:"Dip Belt"},"Rozpiętki na wyciągu z dołu (góra klatki)":{steps:["Set both cable arms to the low position and grab the handles.","Stand in a split stance, one foot forward, lean slightly forward.","With slightly bent elbows, raise your hands up and together in an arc.","Squeeze the upper chest at the top and return under control."],proTip:"Drive the hands upward (like clapping overhead) to target the clavicular chest.",targetMuscles:["Upper chest","Front delts"],primaryMuscle:"chest",equipment:"Cable Machine"},"Rozpiętki na wyciągu z góry (dół klatki)":{steps:["Set both cable arms to the high position and grab the handles.","Stand in a split stance with your torso leaning slightly forward.","With slightly bent elbows, bring your hands down and together in front of your hips.","Squeeze the lower chest and return under control to a stretch."],proTip:"Cross your hands at the end of the rep to fully contract the lower chest.",targetMuscles:["Lower chest","Mid chest"],primaryMuscle:"chest",equipment:"Cable Machine"},"Wyciskanie na wyciągu stojąc (góra klatki)":{steps:["Set the cable arms to chest height and grab both handles.","Stand in a staggered stance facing away from the machine, handles by your chest.","Press your hands forward and together until the elbows extend.","Return under control, retracting the shoulder blades at the start."],proTip:"Constant cable tension through the whole range gives a great peak contraction.",targetMuscles:["Chest","Triceps","Front delts"],primaryMuscle:"chest",equipment:"Cable Machine"},"Svend Press (ściskanie talerzy)":{steps:["Stand tall and press two plates (or one) between your flat palms at chest height.","Squeeze the plates hard together throughout the entire movement.","Press the plates straight out in front of you until your arms extend.","Return slowly to your chest without easing the palm pressure."],proTip:"The harder you squeeze the plates, the stronger the inner chest contraction.",targetMuscles:["Inner chest","Front delts"],primaryMuscle:"chest",equipment:"Weight Plate"},"Wyciskanie hantli wąsko (chwyt neutralny)":{steps:["Lie on a flat bench holding dumbbells with a neutral grip, the bells touching.","Press the dumbbells firmly together over the middle of your chest.","Lower the dumbbells to your chest without separating them.","Press back up while continuously squeezing the dumbbells together."],proTip:"Constantly pressing the dumbbells together maximizes inner chest tension.",targetMuscles:["Inner chest","Triceps","Front delts"],primaryMuscle:"chest",equipment:"Dumbbells"},"Rozpiętki gumą oporową stojąc":{steps:["Anchor the band behind you at chest height and grab both ends.","Stand in a slight split stance, arms out to the sides with slightly bent elbows.","Bring your arms forward in an arc and join them in front of your chest.","Squeeze the chest and return under control to a stretch."],proTip:"The band gives ascending resistance, so the end contraction is hardest: pause there for a second.",targetMuscles:["Chest","Front delts"],primaryMuscle:"chest",equipment:"Resistance Band"},"Pompki na podwyższeniu (nogi w górze)":{steps:["Rest your feet on a bench or elevation, hands on the floor slightly wider than shoulders.","Brace your abs and glutes to keep your body in a straight line.","Lower your chest to the floor, bending elbows at ~45 degrees.","Press back up until your elbows extend."],proTip:"The higher the feet, the greater the load on the upper chest and shoulders.",targetMuscles:["Upper chest","Front delts","Triceps"],primaryMuscle:"chest",equipment:"Bodyweight"},"Pompki diamentowe":{steps:["Get into a plank with your hands under your chest, thumbs and index fingers touching to form a diamond.","Brace your abs and keep your body in one line.","Lower your chest to your hands keeping the elbows close to the torso.","Press back up, squeezing the inner chest and triceps."],proTip:"Keep elbows tucked: flaring them shifts work to the shoulders and strains the wrists.",targetMuscles:["Inner chest","Triceps","Front delts"],primaryMuscle:"chest",equipment:"Bodyweight"},"Ściąganie drążka podchwytem (wąsko)":{steps:["Grip the bar underhand at shoulder width and sit, locking thighs under the pads.","Lift the chest, retract the shoulder blades and pull the bar to the upper chest.","Pause for a second in the squeeze, feeling tension in the back.","Slowly extend the arms to a full stretch of the lats."],proTip:"Keep elbows close to the torso to engage the lower lats more strongly.",targetMuscles:["Latissimus dorsi","Biceps","Teres major"],primaryMuscle:"back",equipment:"Lat Pulldown Machine"},"Ściąganie drążka neutralnym chwytem":{steps:["Attach a V-handle to the high pulley and grab it with a neutral grip.","Sit down, lock the thighs and lean the torso slightly back.","Pull the handle to the sternum, driving the elbows down and back.","Slowly return to the starting position, controlling the weight."],proTip:"A neutral grip spares the wrists and evenly loads the back and brachialis.",targetMuscles:["Latissimus dorsi","Teres major","Brachialis"],primaryMuscle:"back",equipment:"Lat Pulldown Machine with V-handle"},"Podciąganie wspomagane na maszynie":{steps:["Set the assistance weight and kneel or stand on the machine pad.","Grab the top handles with an overhand grip at shoulder width.","Pull yourself up, driving the chest to the handles and retracting the scapulae.","Lower under control until the arms are fully extended."],proTip:"Gradually reduce the assistance to progress toward bodyweight pull-ups.",targetMuscles:["Latissimus dorsi","Biceps","Teres major"],primaryMuscle:"back",equipment:"Assisted Pull-Up Machine"},"Wiosłowanie T-bar wąskim chwytem (uchwyt V)":{steps:["Straddle the T-bar and grab the V-handle with a close, neutral grip.","Hinge the torso to about 45 degrees with a flat back and slightly bent knees.","Pull the weight to the abdomen, squeezing the shoulder blades together.","Lower under control to a full stretch of the back."],proTip:"Keep the chest up throughout the movement to avoid rounding the spine.",targetMuscles:["Latissimus dorsi","Trapezius","Rhomboids"],primaryMuscle:"back",equipment:"T-Bar Row Platform with V-handle"},"Wiosłowanie na maszynie jednorącz (plate-loaded)":{steps:["Sit sideways to the machine and rest the chest against the pad.","Grab one handle and let the arm stretch the back forward.","Pull the handle to the hip, driving the elbow close to the body.","Return slowly under control and repeat on the other side."],proTip:"Unilateral work corrects strength imbalances between sides of the back.",targetMuscles:["Latissimus dorsi","Rhomboids","Rear deltoid"],primaryMuscle:"back",equipment:"Hammer Strength Plate-Loaded Machine"},"Wiosłowanie w podporze na ławce skośnej (chest-supported)":{steps:["Set the bench to about 30-45 degrees and lie face down on it.","Grab the dumbbells, hanging freely beneath the shoulders.","Pull the dumbbells to the hips, retracting the shoulder blades.","Lower under control to a full stretch."],proTip:"Chest support eliminates hip cheating and isolates the back.",targetMuscles:["Rhomboids","Latissimus dorsi","Trapezius"],primaryMuscle:"back",equipment:"Dumbbells + Incline Bench"},"Wiosłowanie Meadowsa":{steps:["Stand perpendicular to the end of a landmine barbell and hinge at the hips.","Grab the bar end with an overhand grip, resting the free hand on the thigh.","Pull the bar end up and toward the hip, driving the elbow high.","Lower under control to a full stretch and repeat."],proTip:"A high elbow and a strong bottom stretch maximize lat engagement.",targetMuscles:["Latissimus dorsi","Rear deltoid","Trapezius"],primaryMuscle:"back",equipment:"Landmine Barbell"},"Martwy ciąg częściowy z podstawek (Rack Pull)":{steps:["Set the bar on blocks at a height just below the knees.","Grip the bar at shoulder width, chest up, back flat.","Extend the hips and knees, pulling the bar along the thighs to full lockout.","Lower the bar under control back onto the blocks."],proTip:"The shortened range lets you load heavy and hit the upper back hard.",targetMuscles:["Erector spinae","Trapezius","Latissimus dorsi"],primaryMuscle:"back",equipment:"Barbell + Power Rack/Blocks"},"Wiosłowanie w maszynie Smitha":{steps:["Set the Smith bar low and grip it overhand slightly wider than shoulders.","Hinge the torso to about 45 degrees, back flat, knees slightly bent.","Unlock the bar and pull it to the lower chest, retracting the scapulae.","Lower under control to a full stretch of the arms."],proTip:"The fixed bar path lets you focus on retracting the scapulae without stabilizing.",targetMuscles:["Latissimus dorsi","Rhomboids","Trapezius"],primaryMuscle:"back",equipment:"Smith Machine"},"Australijskie podciąganie (Inverted Row)":{steps:["Set the bar at hip height and lie beneath it, gripping it overhand.","Straighten the body in a straight line, resting on the heels.","Pull the chest to the bar, retracting the shoulder blades.","Lower under control to a full extension of the arms."],proTip:"The lower the bar, the harder the exercise; adjust the angle to your level.",targetMuscles:["Rhomboids","Latissimus dorsi","Rear deltoid"],primaryMuscle:"back",equipment:"Bodyweight + Bar in Rack"},"Szrugi w maszynie Smitha":{steps:["Set the Smith bar at thigh height and grip it overhand at shoulder width.","Stand tall, arms straight, bar in front of the thighs.","Shrug the shoulders straight up toward the ears, squeezing the traps at the top.","Lower the shoulders under control to a full stretch."],proTip:"Do not roll the shoulders; keep the motion strictly vertical for joint safety.",targetMuscles:["Upper trapezius","Levator scapulae"],primaryMuscle:"back",equipment:"Smith Machine"},"Szrugi na wyciągu":{steps:["Attach a bar to the low cable and grip it overhand, standing close to the pulley.","Stand tall with knees slightly bent and arms straight.","Shrug the shoulders up, squeezing the traps at the top.","Lower the shoulders under control, keeping constant cable tension."],proTip:"The cable keeps tension at the bottom, which a barbell does not provide.",targetMuscles:["Upper trapezius","Levator scapulae"],primaryMuscle:"back",equipment:"Low Cable with Straight Bar"},"Pullover na maszynie":{steps:["Sit in the machine and set the seat so the upper arms rest on the pads.","Grab the handles and let the arms stretch up overhead.","Pull the pads in an arc down toward the hips using the lats.","Slowly return to the stretch, controlling the weight."],proTip:"Initiate the movement with the elbows and lats, do not over-bend the wrists.",targetMuscles:["Latissimus dorsi","Teres major","Pectoralis"],primaryMuscle:"back",equipment:"Pullover Machine (Nautilus)"},"Wiosłowanie na lince stojąc (Face Pull do twarzy)":{steps:["Set the rope at face height and grab both ends with a neutral grip.","Step back to tension the cable and stand with a slight stagger.","Pull the rope to the face, separating the ends and externally rotating the arms.","Slowly return to arm extension, controlling the weight."],proTip:"Keep elbows high and separate the rope ends at the face for shoulder health.",targetMuscles:["Rear deltoid","Middle trapezius","Rhomboids"],primaryMuscle:"back",equipment:"High Cable with Rope"},"Martwy ciąg sumo (akcent na plecy)":{steps:["Stand in a wide stance, toes pointed out, bar over the midfoot.","Grip the bar inside the knees, chest up, back flat.","Drive the feet into the floor and extend the hips and knees together.","Lock out at the top and lower the bar under control along the legs."],proTip:"The shorter range versus conventional loads the erectors and traps heavily.",targetMuscles:["Erector spinae","Trapezius","Glutes"],primaryMuscle:"back",equipment:"Barbell"},"Martwy ciąg z deficytu":{steps:["Stand on a 3-5 cm platform with the bar over the midfoot.","Grip the bar at shoulder width, descending lower than conventional, back flat.","Brace the back and extend the hips, pulling the bar along the legs.","Lock out at the top and lower under control back to the floor."],proTip:"The longer range strengthens the bottom pull and erector tension.",targetMuscles:["Erector spinae","Trapezius","Latissimus dorsi"],primaryMuscle:"back",equipment:"Barbell + Platform"},"Wymachy kettlebell (posterior chain)":{steps:["Stand with feet apart and the kettlebell on the floor in front of you.","Hinge at the hips, grab the handle and hike the kettlebell between the legs.","Explosively extend the hips, swinging the kettlebell to chest height.","Let it fall back and flow smoothly into the next repetition."],proTip:"Power comes from the hips, not the arms; the arms just guide the kettlebell.",targetMuscles:["Erector spinae","Glutes","Hamstrings"],primaryMuscle:"back",equipment:"Kettlebell"},"Wyciskanie barków na maszynie Hammer Strength (jednorącz)":{steps:["Sit in the machine and set seat height so the handles are at shoulder level.","Grab one handle and brace the other hand on the machine frame or your knee.","Press the arm overhead to near full extension without locking the elbow.","Lower the handle slowly back to the starting position under control.","Complete all reps on one side, then switch arms."],proTip:"Unilateral pressing evens out strength imbalances between shoulders and forces the core to stabilize harder.",targetMuscles:["Anterior deltoids","Lateral deltoids","Triceps"],primaryMuscle:"shoulders",equipment:"Hammer Strength Machine"},"Wyciskanie nad głowę w Smith (Smith OHP)":{steps:["Position a bench or stand under the Smith bar so the bar is at collarbone height.","Grip the bar slightly wider than shoulder width with elbows angled slightly forward.","Unrack the bar and press it vertically overhead to full arm extension.","Lower the bar under control to chin level.","Repeat while keeping the torso braced and avoiding excessive backward lean."],proTip:"The Smith's fixed path lets you safely load heavier and focus on pressing instead of balancing.",targetMuscles:["Anterior deltoids","Lateral deltoids","Triceps"],primaryMuscle:"shoulders",equipment:"Smith Machine"},"Odwrotne rozpiętki na maszynie (Reverse Pec Deck)":{steps:["Sit facing the pec deck pad with your chest against the backrest.","Grab the handles at shoulder height with arms extended in front of you.","Sweep your arms back in a wide arc while squeezing the shoulder blades.","Pause at maximum opening for a second.","Return your arms forward slowly, controlling the resistance."],proTip:"Slightly bent elbows and driving from the rear delt, not the scapula, best isolate the posterior head.",targetMuscles:["Posterior deltoids","Rhomboids","Lower trapezius"],primaryMuscle:"shoulders",equipment:"Pec Deck Machine"},"Wznosy bokiem jednorącz na wyciągu dolnym":{steps:["Set the cable handle to the lowest position and stand sideways to the machine.","Grab the handle with the hand farther from the stack, arm lowered in front of the thigh.","Raise the arm out to the side up to shoulder height with a slight elbow bend.","Pause at the top, feeling tension in the lateral delt.","Lower under control and repeat, then switch sides."],proTip:"The cable keeps constant tension throughout the range, which dumbbells lack at the bottom.",targetMuscles:["Lateral deltoids","Upper trapezius"],primaryMuscle:"shoulders",equipment:"Cable Machine"},"Podciąganie sztangi wzdłuż tułowia (Upright Row)":{steps:["Stand tall holding a barbell with an overhand shoulder-width grip, arms extended.","Guide the bar vertically up along the torso, lifting the elbows out to the sides.","Pull the bar to sternum height with elbows higher than the hands.","Pause at the top and slowly lower the barbell.","Repeat, keeping the bar close to the body throughout the movement."],proTip:"Don't pull the bar above sternum height to avoid impingement in the shoulder joint.",targetMuscles:["Lateral deltoids","Upper trapezius","Anterior deltoids"],primaryMuscle:"shoulders",equipment:"Barbell"},"Podciąganie wzdłuż tułowia na wyciągu (Cable Upright Row)":{steps:["Attach a straight bar to the low cable and stand facing the machine.","Grab the bar with an overhand shoulder-width grip, arms extended.","Pull the bar vertically up along the torso, lifting the elbows out to the sides.","Bring the bar to sternum height and pause for a second.","Lower under control and repeat."],proTip:"The cable's constant tension keeps load on the delts even in the bottom phase.",targetMuscles:["Lateral deltoids","Upper trapezius","Anterior deltoids"],primaryMuscle:"shoulders",equipment:"Cable Machine"},"Podciąganie hantli wzdłuż tułowia (Dumbbell Upright Row)":{steps:["Stand tall holding dumbbells overhand in front of your thighs, hands close together.","Pull the dumbbells vertically up along the torso, leading with the elbows out and up.","Bring the dumbbells to upper-chest height with elbows higher than the hands.","Pause at the top and slowly lower the dumbbells.","Repeat, keeping the dumbbells close to the body."],proTip:"Dumbbells allow more wrist freedom than a barbell, easing joint stress during the pull.",targetMuscles:["Lateral deltoids","Upper trapezius","Anterior deltoids"],primaryMuscle:"shoulders",equipment:"Dumbbells"},"Cuban Press (rotacja zewnętrzna z wyciskaniem)":{steps:["Stand tall with dumbbells, lift the elbows out to shoulder height (like the start of an upright row).","Using the elbows as a pivot, externally rotate the forearms upward.","From that position press the dumbbells overhead to full arm extension.","Reverse the motion: lower the dumbbells, internally rotate and return to the start.","Repeat smoothly using a moderate load."],proTip:"It's an excellent rotator-cuff strengthener, so keep the load light and the control full.",targetMuscles:["Posterior deltoids","Rotator cuff","Lateral deltoids"],primaryMuscle:"shoulders",equipment:"Dumbbells"},"Z-Press (wyciskanie siedząc na podłodze)":{steps:["Sit on the floor with legs extended in a V position.","Take a barbell from collarbone level with elbows pointing forward.","Keeping the torso upright, press the bar overhead to full arm extension.","Lower the bar under control to chin height.","Repeat without leaning back or using leg drive."],proTip:"No leg support forces the core and shoulders to do all the work, eliminating hip cheating.",targetMuscles:["Anterior deltoids","Lateral deltoids","Core"],primaryMuscle:"shoulders",equipment:"Barbell"},"Landmine Press (wyciskanie jednorącz)":{steps:["Anchor one end of the barbell in a landmine, lift the other end up to your shoulder.","Stand with feet slightly apart, holding the bar end with one hand at your collarbone.","Press the bar up and forward along an arc, extending the arm.","Slowly return the bar to your shoulder under control.","Complete all reps, then switch hands."],proTip:"The landmine's angled path is gentler on the shoulders than vertical pressing, great for mobility issues.",targetMuscles:["Anterior deltoids","Lateral deltoids","Core","Triceps"],primaryMuscle:"shoulders",equipment:"Barbell (Landmine)"},"Pompki w pozycji szczytowej (Pike Push-up)":{steps:["Get into a push-up position, then raise your hips high to form an inverted V (downward dog).","Place hands slightly wider than shoulders with legs straight.","Bending the elbows, lower your head toward the floor between your hands.","When the top of your head nearly touches the floor, press back up.","Repeat, keeping the hips high throughout the movement."],proTip:"The higher the hips and more vertical the torso, the more shoulder load; a great progression toward handstand push-ups.",targetMuscles:["Anterior deltoids","Triceps","Upper chest"],primaryMuscle:"shoulders",equipment:"Bodyweight"},"Wyciskanie hantli neutralnym chwytem nad głowę":{steps:["Sit on a bench with backrest, holding dumbbells at shoulder height with a neutral grip (palms facing each other).","Angle the elbows slightly forward rather than fully out to the sides.","Press the dumbbells overhead, keeping the palms facing each other throughout.","Extend the arms without locking the elbows, then lower the dumbbells slowly.","Repeat, keeping the torso braced and against the bench."],proTip:"The neutral grip places the shoulders in a more natural position and spares the joint if pronated pressing hurts.",targetMuscles:["Anterior deltoids","Lateral deltoids","Triceps"],primaryMuscle:"shoulders",equipment:"Dumbbells"},"Wznosy bokiem z gumą oporową":{steps:["Stand on the middle of the band with both feet, holding its ends at your thighs.","Keep the elbows slightly bent and palms facing the thighs.","Raise the arms out to the sides up to shoulder height, stretching the band.","Pause at the top of the movement for a second.","Lower the arms slowly, controlling the band as it returns."],proTip:"Band resistance increases with range, so tension peaks at the top, exactly where the lateral delt works hardest.",targetMuscles:["Lateral deltoids","Upper trapezius"],primaryMuscle:"shoulders",equipment:"Resistance Band"},"Wznosy sztangi w przód (Barbell Front Raise)":{steps:["Stand tall holding a barbell with an overhand shoulder-width grip, bar resting on the thighs.","Keep the arms extended with a minimal elbow bend.","Raise the bar in front of you to shoulder height, driving from the anterior delts.","Pause briefly when the bar is at eye/shoulder height.","Lower the bar slowly to the thighs and repeat without swinging the torso."],proTip:"Don't raise the bar above shoulder line to keep tension on the front delt rather than shifting it to the traps.",targetMuscles:["Anterior deltoids","Upper chest"],primaryMuscle:"shoulders",equipment:"Barbell"},"Wznosy krążka w przód (Plate Front Raise)":{steps:["Stand tall holding a plate with both hands on its sides (at 3 and 9 o'clock), arms down.","Keep the elbows slightly bent and the plate in front of the thighs.","Raise the plate in front of you to eye level, driving from the anterior delts.","Pause at the top of the movement for a second.","Lower the plate slowly to the thighs and repeat without swinging the torso."],proTip:"Gripping the plate at its sides also engages the wrist stabilizers and lets you fine-tune the load.",targetMuscles:["Anterior deltoids","Upper chest"],primaryMuscle:"shoulders",equipment:"Weight Plate"},"Wznosy 6-kierunkowe (6-Way Raise)":{steps:["Stand tall with light dumbbells, arms down at your sides.","Phase 1: raise the dumbbells out to the sides to shoulder height, then sweep the arms to the front.","Phase 2: lower the dumbbells in front of you to the thighs.","Phase 3: raise the dumbbells to the front to shoulder height, then sweep the arms out to the sides.","Lower the dumbbells out to the sides down to the thighs; that is one 6-way rep, use very light weight."],proTip:"It's a finisher that hits all three deltoid heads, so the weight must be minimal.",targetMuscles:["Anterior deltoids","Lateral deltoids","Posterior deltoids"],primaryMuscle:"shoulders",equipment:"Dumbbells"},"Przysiad przedni ze sztangą (Front Squat)":{steps:["Rest the bar on the front of your shoulders, elbows high, with a clean or cross grip.","Set feet shoulder-width, chest tall, brace your core.","Descend keeping the torso upright, knees tracking over the toes.","Reach parallel or below and drive up through the heels."],proTip:"Keep your elbows high throughout, since dropping elbows let the bar roll forward.",targetMuscles:["Quadriceps","Gluteus maximus","Core"],primaryMuscle:"quads",equipment:"Barbell"},"Prasa nożna pozioma (siedząc)":{steps:["Sit in the horizontal machine with your back against the pad, feet hip-width on the platform.","Release the safeties and let the platform travel toward you under control.","Bend the knees to about 90 degrees without lifting your hips.","Press the platform away through your heels, avoiding locking the knees."],proTip:"The horizontal version loads the spine less than the angled press, good with back issues.",targetMuscles:["Quadriceps","Gluteus maximus","Hamstrings"],primaryMuscle:"quads",equipment:"Horizontal Leg Press Machine"},"Prasa nożna pionowa (leżąc)":{steps:["Lie under the platform with hips beneath the load and feet on the platform above you.","Release the safeties and lower the platform by bending the knees toward your chest.","Stop when thighs approach the torso, keeping the lower back flat.","Press the platform straight up driving through the whole foot."],proTip:"The vertical press gives a big range of motion but needs a light start load.",targetMuscles:["Quadriceps","Gluteus maximus","Hamstrings"],primaryMuscle:"quads",equipment:"Vertical Leg Press Machine"},"Hack Squat odwrotny (twarzą do oparcia)":{steps:["Position yourself facing the hack squat pad, shoulders under the pads.","Place feet slightly forward on the platform with hips set back.","Descend by bending the knees and hips, emphasizing the glutes.","Drive up through the heels and squeeze the glutes at the top."],proTip:"Facing the pad recruits the glutes more than the standard hack squat.",targetMuscles:["Gluteus maximus","Quadriceps","Hamstrings"],primaryMuscle:"glutes",equipment:"Hack Squat Machine"},"Pendulum Squat (maszyna wahadłowa)":{steps:["Set your shoulders under the pads, back against the platform, feet on the footplate.","Release the safeties and descend along the arc by bending the knees.","Go deep keeping heels down and back against the pad.","Drive up along the arc pressing through the midfoot."],proTip:"The arced path keeps constant tension on the quads through the full range.",targetMuscles:["Quadriceps","Gluteus maximus"],primaryMuscle:"quads",equipment:"Pendulum Squat Machine"},"Przysiad Belt Squat (z pasem biodrowym)":{steps:["Attach the hip belt to the load and stand on the machine platforms.","Hold the handles, keep the torso upright and core braced.","Squat down by bending knees and hips while the load pulls from the hips.","Drive up through the heels to full hip extension."],proTip:"The belt squat loads the legs without spinal compression, ideal for back recovery.",targetMuscles:["Quadriceps","Gluteus maximus","Hamstrings"],primaryMuscle:"quads",equipment:"Belt Squat Machine"},"Wyprosty nóg na maszynie jednonóż":{steps:["Sit in the machine with the pad on one ankle and the other leg set aside.","Hold the handles, back against the pad.","Extend the single leg to full lockout, squeezing the quad at the top.","Lower under control and repeat, then switch legs."],proTip:"The single-leg version fixes strength imbalances and improves mind-muscle connection.",targetMuscles:["Quadriceps","Rectus femoris"],primaryMuscle:"quads",equipment:"Leg Extension Machine"},"Uginanie nóg stojąc jednonóż na maszynie":{steps:["Stand in the machine with the pad behind one calf and hip against the support.","Hold the handles, keep the torso stable.","Curl the leg pulling the heel toward the glute, squeezing the hamstring.","Lower under control and repeat, then switch legs."],proTip:"The standing single-leg version gives clean isolated hamstring work without cheating.",targetMuscles:["Biceps femoris","Semitendinosus","Semimembranosus"],primaryMuscle:"hamstrings",equipment:"Standing Leg Curl Machine"},"Przysiad w suwnicy Smitha":{steps:["Set the bar on your shoulders in the Smith, feet slightly ahead of the bar line.","Unhook the bar by rotating the wrists, brace your core.","Squat down along the guide rails bending knees and hips.","Drive up through the heels to standing and re-rack the bar at the top."],proTip:"Feet forward in the Smith emphasize the quads and make balance easier.",targetMuscles:["Quadriceps","Gluteus maximus","Hamstrings"],primaryMuscle:"quads",equipment:"Smith Machine"},"Wykrok w suwnicy Smitha":{steps:["Set the bar on your shoulders and step one foot forward under the bar.","Unhook the bar, keep the torso upright.","Descend by bending the front knee to about 90 degrees.","Drive up through the front heel, repeat, then switch legs."],proTip:"The Smith stabilizes the path, so focus on depth and front-leg drive.",targetMuscles:["Quadriceps","Gluteus maximus","Hamstrings"],primaryMuscle:"quads",equipment:"Smith Machine"},"Glute-Ham Raise (GHR)":{steps:["Set up on the GHD with feet against the plate and knees behind the pad.","Keep the torso aligned with the thighs at the start.","Lower the torso forward under control to horizontal, extending the knees.","Bend the knees and pull the torso back up using the hamstrings."],proTip:"If a full GHR is too hard, push off the floor with your hands at the bottom.",targetMuscles:["Biceps femoris","Gluteus maximus","Calves"],primaryMuscle:"hamstrings",equipment:"Glute-Ham Developer"},"Nordic Hamstring Curl":{steps:["Kneel down with ankles anchored under a load or held by a partner.","Keep torso and hips in line with the thighs, core braced.","Lower forward slowly, resisting with the hamstrings as long as possible.","When tension fails catch yourself with the hands and push back to start."],proTip:"The eccentric phase matters most, so resist as slowly as possible, do not drop.",targetMuscles:["Biceps femoris","Semitendinosus","Gluteus maximus"],primaryMuscle:"hamstrings",equipment:"Bodyweight"},"Przysiad pistolet (jednonóż)":{steps:["Stand on one leg with the other extended forward off the ground.","Reach your arms in front for balance.","Descend on one leg until the thigh is below parallel.","Drive up through the standing heel back to full extension."],proTip:"Start holding a TRX or elevated before mastering the full range.",targetMuscles:["Quadriceps","Gluteus maximus","Core"],primaryMuscle:"quads",equipment:"Bodyweight"},"Przysiad z masą ciała (Air Squat)":{steps:["Stand shoulder-width with arms in front or on the hips.","Brace your core, chest tall.","Descend by sending the hips back until thighs are parallel to the floor.","Drive up through the heels to full extension."],proTip:"Ideal as a warm-up and for grooving the squat pattern before loading.",targetMuscles:["Quadriceps","Gluteus maximus","Hamstrings"],primaryMuscle:"quads",equipment:"Bodyweight"},"Sissy Squat na maszynie":{steps:["Set your legs under the sissy machine pads with heels on the footplate.","Keep torso and thighs in one line, core braced.","Lean back by bending the knees and pushing them forward.","Return to upright by contracting the quads at the end."],proTip:"The machine fixes the path and offloads the knees versus the free version.",targetMuscles:["Quadriceps","Rectus femoris"],primaryMuscle:"quads",equipment:"Sissy Squat Machine"},"Wejścia przodem na skrzynię ze sztangielkami":{steps:["Hold dumbbells at your sides and stand facing a box or step.","Plant your whole foot on the box, knee tracking over the toes.","Drive up through the heel of the top leg to full standing.","Step down under control and repeat, alternating or per-leg sets."],proTip:"Minimize push-off from the trailing leg, all work should come from the top leg.",targetMuscles:["Quadriceps","Gluteus maximus","Hamstrings"],primaryMuscle:"quads",equipment:"Dumbbells"},"Przysiad do skrzyni (Box Squat)":{steps:["Place a box behind you, bar on your shoulders, feet wider than shoulders.","Send the hips back as you descend toward the box.","Sit lightly on the box without losing torso tension.","Explosively drive up through the heels to full hip extension."],proTip:"Do not crash onto the box, control the descent and keep tension.",targetMuscles:["Gluteus maximus","Quadriceps","Hamstrings"],primaryMuscle:"glutes",equipment:"Barbell"},"Przysiad Zercher (sztanga w zgięciach łokci)":{steps:["Cradle the bar in the crooks of your elbows at the chest, hands clasped.","Set feet shoulder-width, torso upright, core braced.","Descend deep into the squat with elbows between the knees.","Drive up through the heels keeping the chest tall."],proTip:"Wrapping the bar with a towel reduces elbow discomfort at heavier loads.",targetMuscles:["Quadriceps","Gluteus maximus","Core"],primaryMuscle:"quads",equipment:"Barbell"},"Przysiad sumo z kettlebell":{steps:["Take a wide stance, toes out, holding the kettlebell with both hands between your legs.","Chest tall, core braced.","Descend sending the hips back, knees tracking over the toes.","Drive up through the heels squeezing glutes and adductors at the top."],proTip:"A wide stance with toes out recruits the adductors and glutes more.",targetMuscles:["Gluteus maximus","Adductors","Quadriceps"],primaryMuscle:"glutes",equipment:"Kettlebell"},"Wykroki chodzone z hantlami (długi krok)":{steps:["Hold dumbbells at your sides and take a long step forward.","Lower until the trailing knee nears the floor.","Drive up through the front heel and step through into the next long stride.","Continue walking while keeping the torso upright."],proTip:"A longer stride shifts emphasis to the glutes, a shorter one to the quads.",targetMuscles:["Gluteus maximus","Quadriceps","Hamstrings"],primaryMuscle:"glutes",equipment:"Dumbbells"},"Wypychanie bioder na maszynie Glute Drive":{steps:["Sit on the machine with your back against the pad and the lever low across your hips.","Place your feet on the platform hip-width apart and drive through your heels.","Push your hips up by squeezing the glutes to full extension.","Pause at the top for a second, then lower your hips under control."],proTip:"At the top, slightly tuck the pelvis to fully shorten the glute without hyperextending the lower back.",targetMuscles:["Gluteus maximus","Hamstrings","Quadriceps"],primaryMuscle:"glutes",equipment:"Glute Drive Machine"},"Hip Thrust w maszynie Smith":{steps:["Rest your upper back on a bench and position the Smith bar low across your hips with a pad.","Set your feet flat, hip-width apart, slightly in front of your knees.","Unrack the bar and drive your hips up until your torso is parallel to the floor.","Squeeze the glutes at the top, then lower your hips under control."],proTip:"The fixed Smith bar path lets you safely add load without balancing, ideal for overloading the glutes.",targetMuscles:["Gluteus maximus","Hamstrings","Gluteus medius"],primaryMuscle:"glutes",equipment:"Smith Machine"},"Odwodzenie ud na maszynie z pochyleniem tułowia":{steps:["Sit on the abductor machine and lean your torso forward against the pads.","The forward lean shifts emphasis onto the upper glutes.","Push your knees outward against the resistance through a full range.","Pause briefly, then return to the start under control."],proTip:"Leaning 30-45 degrees forward shifts tension from the TFL onto the gluteus medius.",targetMuscles:["Gluteus medius","Gluteus minimus","Tensor fasciae latae"],primaryMuscle:"glutes",equipment:"Hip Abductor Machine"},"Kickback pośladka na maszynie":{steps:["Place your foot on the machine's moving platform and rest your torso against the pads.","Grip the handles for stability and keep your back neutral.","Push your foot back and up, squeezing the glute to full hip extension.","Pause at the top, then return slowly to the start."],proTip:"Keep the knee slightly bent and lead with the heel to isolate the glute without lower-back help.",targetMuscles:["Gluteus maximus","Hamstrings"],primaryMuscle:"glutes",equipment:"Glute Kickback Machine"},"Przeciąganie linki między nogami (Cable Pull-Through)":{steps:["Set the rope attachment low and stand facing away from the cable in a straddle stance.","Reach between your legs, grab the rope, and step a few feet forward.","Hinge at the hips, sending your hips back while leaning your torso forward.","Drive your hips forward, squeezing the glutes to full extension."],proTip:"Drive the movement with your hips, not your arms, your hands just hold the rope like hooks.",targetMuscles:["Gluteus maximus","Hamstrings","Erector spinae"],primaryMuscle:"glutes",equipment:"Cable Machine"},"Mostek pośladkowy na jednej nodze":{steps:["Lie on your back, plant one foot flat and extend the other leg up.","Brace your core and keep your pelvis in a neutral position.","Drive your hips up through the heel of the planted leg, keeping the other leg raised.","Squeeze the glute at the top, then lower your hips under control."],proTip:"Keep your hips level, do not let the side of the raised leg drop.",targetMuscles:["Gluteus maximus","Hamstrings","Core"],primaryMuscle:"glutes",equipment:"Bodyweight"},"Frog Pump (mostek z rozłożonymi kolanami)":{steps:["Lie on your back, press the soles of your feet together and let your knees fall outward.","Bring your feet closer to your glutes with knees pointing out.","Drive your hips up while squeezing the glutes hard.","Pause at the top for a second, then lower your hips under control."],proTip:"The frog position with splayed knees forces more external rotation, hitting the glutes harder.",targetMuscles:["Gluteus maximus","Gluteus medius"],primaryMuscle:"glutes",equipment:"Bodyweight"},"Wykrok ukośny (Curtsy Lunge)":{steps:["Stand tall with dumbbells in your hands, feet hip-width apart.","Step one leg diagonally behind, crossing it behind the standing leg.","Lower by bending both knees, stretching the rear-leg hip.","Push through the front heel to return to the starting position."],proTip:"Crossing the leg diagonally back strongly targets the gluteus medius, key for hip shaping.",targetMuscles:["Gluteus medius","Gluteus maximus","Quadriceps"],primaryMuscle:"glutes",equipment:"Dumbbells"},"Wysoki step-up z hantlami":{steps:["Stand in front of a high box or bench with dumbbells in your hands.","Place your whole foot on the box with the knee and hip deeply bent.","Push through the heel of the top leg to step up to full extension.","Lower the other leg back to the floor under control."],proTip:"The higher the box, the deeper the hip flexion and more glute work, do not push off with the bottom leg.",targetMuscles:["Gluteus maximus","Quadriceps","Hamstrings"],primaryMuscle:"glutes",equipment:"Dumbbells"},"Wykrok w tył z akcentem na pośladek":{steps:["Stand tall with dumbbells and hinge your torso slightly forward from the hips.","Take a long step back with one leg and lower until the rear knee nearly touches the floor.","Keep your weight on the heel of the front leg.","Push strongly through the front heel, squeezing the glute as you stand."],proTip:"A longer back step and slight torso lean shifts the work from quads to the glutes.",targetMuscles:["Gluteus maximus","Quadriceps","Hamstrings"],primaryMuscle:"glutes",equipment:"Dumbbells"},"Rumuński martwy ciąg z akcentem na pośladek":{steps:["Hold the barbell in front of your thighs with an overhand grip, feet hip-width apart.","Push your hips back hard, letting the bar slide down close to your legs.","Lower until you feel a stretch in the hamstrings and glutes, back flat.","Drive your hips forward, squeezing the glutes to full extension."],proTip:"Consciously push the hips far back, the bigger the hinge, the deeper the glute stretch.",targetMuscles:["Gluteus maximus","Hamstrings","Erector spinae"],primaryMuscle:"glutes",equipment:"Barbell"},"Wymachy kettlebell":{steps:["Stand with feet slightly wider than hips, kettlebell on the floor in front of you.","Hinge at the hips, grab the kettlebell with both hands and hike it between your legs.","Explosively snap your hips forward, the drive swings the kettlebell to chest height.","Let the kettlebell drop, hinging at the hips again on the way down."],proTip:"The swing is hip-driven, not arm-driven, the hip snap launches the weight.",targetMuscles:["Gluteus maximus","Hamstrings","Erector spinae","Core"],primaryMuscle:"glutes",equipment:"Kettlebell"},"Kickback pośladka z gumą oporową":{steps:["Get into a hands-and-knees position, looping the band over your foot and under your hands.","Keep your back flat, core braced, and knee bent at a right angle.","Push your leg back and up against the band, squeezing the glute.","Pause at the top, then return to the start under control."],proTip:"Do not hyperextend the lower back, the rep ends at hip extension, beyond that the back takes over.",targetMuscles:["Gluteus maximus","Hamstrings"],primaryMuscle:"glutes",equipment:"Resistance Band"},"Hip Thrust w rozstawie B-stance":{steps:["Rest your upper back on a bench and place a dumbbell across your hips.","Plant one foot flat as the working leg, set the other back resting only on the heel.","Drive your hips up mainly through the working foot, the back leg only assists for balance.","Squeeze the working-side glute at the top, then lower your hips under control."],proTip:"The B-stance bridges to single-leg work, keep most of the load on the front foot to overload one glute.",targetMuscles:["Gluteus maximus","Hamstrings","Gluteus medius"],primaryMuscle:"glutes",equipment:"Dumbbell"},"Uginanie skoncentrowane (Concentration Curl)":{steps:["Sit down, spread your legs and brace your elbow against the inner thigh.","Hold the dumbbell with your arm hanging straight down.","Curl the elbow, bringing the dumbbell toward the shoulder with full supination.","Pause at the top and squeeze the biceps, then lower slowly."],proTip:"Keep the elbow glued to the thigh throughout to fully isolate the biceps.",targetMuscles:["Biceps (short head)","Brachialis"],primaryMuscle:"biceps",equipment:"Dumbbell"},"Uginanie na pająku (Spider Curl)":{steps:["Lie chest-down on an incline bench set to about 45 degrees.","Let your arms hang straight down while holding an EZ bar.","Curl the elbows, bringing the bar up without moving the shoulders.","Squeeze the biceps at the top and lower slowly to full extension."],proTip:"The position removes momentum, keeping constant tension during the contraction.",targetMuscles:["Biceps (short head)","Brachialis"],primaryMuscle:"biceps",equipment:"EZ Bar"},"Uginanie z dociąganiem (Drag Curl)":{steps:["Stand tall holding a barbell with a shoulder-width underhand grip.","Drive your elbows back, keeping the bar close to your torso.","Let the bar drag up along the body while the elbows travel behind you.","Pause at the top and lower slowly along the same path."],proTip:"Drawing the elbows behind the body emphasizes the long head of the biceps.",targetMuscles:["Biceps (long head)","Brachialis"],primaryMuscle:"biceps",equipment:"Barbell"},"Uginanie bayesowskie na wyciągu (Bayesian Cable Curl)":{steps:["Set the cable handle low, grab it with one hand and face away from the stack.","Step forward so the arm is stretched behind the line of the body.","Curl the elbow with supination, bringing the hand toward the shoulder.","Squeeze the biceps and return slowly to full stretch behind you."],proTip:"Keeping the arm behind the torso maximizes loaded stretch of the long head.",targetMuscles:["Biceps (long head)","Brachialis"],primaryMuscle:"biceps",equipment:"Cable Machine"},"Uginanie hantli na ławce skośnej (Incline Curl)":{steps:["Sit on an incline bench set to about 45-60 degrees.","Let your arms hang freely down, holding dumbbells in a neutral grip.","Curl the elbows with supination, keeping elbows close to the torso.","Squeeze the biceps at the top and lower slowly to full stretch."],proTip:"The reclined torso stretches the long head of the biceps at the bottom.",targetMuscles:["Biceps (long head)","Brachialis"],primaryMuscle:"biceps",equipment:"Dumbbells"},"Uginanie Zottmana (Zottman Curl)":{steps:["Stand tall holding dumbbells with an underhand grip at your sides.","Curl the elbows with supination, bringing the dumbbells to your shoulders.","At the top, rotate your wrists to an overhand grip (pronation).","Lower the dumbbells slowly in the overhand grip, then rotate back."],proTip:"The overhand eccentric phase heavily loads the forearms.",targetMuscles:["Biceps","Brachioradialis","Forearm extensors"],primaryMuscle:"biceps",equipment:"Dumbbells"},"Uginanie ramion na maszynie wyciąg jednorącz (Single-Arm Cable Curl)":{steps:["Set the cable pulley low and grab the handle with one hand.","Stand side-on to the stack with your elbow against your torso.","Curl the elbow with supination, bringing the hand toward the shoulder.","Squeeze the biceps and return slowly to full extension."],proTip:"The cable provides constant tension even at the bottom, unlike dumbbells.",targetMuscles:["Biceps","Brachialis"],primaryMuscle:"biceps",equipment:"Cable Machine"},"Uginanie odwrotne (Reverse Curl)":{steps:["Stand tall holding an EZ bar with a shoulder-width overhand grip.","Keep your elbows at your sides and wrists straight.","Curl the elbows, bringing the bar up without bending the wrists.","Squeeze the forearms at the top and lower slowly."],proTip:"The overhand grip shifts load to the brachioradialis and wrist extensors.",targetMuscles:["Brachioradialis","Forearm extensors","Brachialis"],primaryMuscle:"forearms",equipment:"EZ Bar"},"Uginanie 21-tki (21s)":{steps:["Stand tall holding a barbell with a shoulder-width underhand grip.","Perform 7 reps from the bottom to the midpoint (90-degree elbow).","Perform 7 reps from the midpoint to full contraction.","Finish with 7 full range-of-motion reps."],proTip:"The 21-rep scheme delivers huge volume and pump with a light weight.",targetMuscles:["Biceps","Brachialis"],primaryMuscle:"biceps",equipment:"Barbell"},"Prostowanie ramion zza głowy na wyciągu (Overhead Cable Extension)":{steps:["Attach a rope to the cable and face away from the stack, gripping it overhead.","Lunge forward with hands bent behind your head, elbows pointing forward.","Extend the elbows, pressing the rope up and forward.","Pause at full extension, then return slowly behind your head."],proTip:"The overhead position stretches the long head of the triceps under constant tension.",targetMuscles:["Triceps (long head)","Triceps (lateral head)"],primaryMuscle:"triceps",equipment:"Cable Machine"},"Prostowanie ramion z liną na wyciągu (Rope Pushdown)":{steps:["Attach a rope to the high pulley and grab both ends with a neutral grip.","Stand tall with elbows pinned to your torso.","Extend the elbows downward, spreading the rope ends apart at the bottom.","Squeeze the triceps at full extension and return slowly."],proTip:"Spreading the rope ends at the bottom increases the lateral head contraction.",targetMuscles:["Triceps (lateral head)","Triceps (medial head)"],primaryMuscle:"triceps",equipment:"Cable Machine"},"Prostowanie ramienia na wyciągu jednorącz (Single-Arm Pushdown)":{steps:["Attach a single handle to the high pulley and grab it underhand with one hand.","Stand tall with your elbow pinned to your side.","Extend the elbow downward to full arm extension.","Squeeze the triceps and return slowly under control."],proTip:"The single-arm underhand grip emphasizes the medial head of the triceps.",targetMuscles:["Triceps (lateral head)","Triceps (medial head)"],primaryMuscle:"triceps",equipment:"Cable Machine"},"JM Press (wyciskanie JM)":{steps:["Lie on a flat bench holding a barbell with a close grip over your chest.","Lower the bar toward your upper chest, bending the elbows forward.","Stop the bar just above your neck with elbows low, a hybrid of skull crusher and press.","Drive the bar back up by extending the elbows."],proTip:"The JM Press blends a close-grip press with a skull crusher, heavily loading the triceps.",targetMuscles:["Triceps","Upper chest","Front delts"],primaryMuscle:"triceps",equipment:"Barbell"},"Tate Press (wyciskanie Tate)":{steps:["Lie on a flat bench holding dumbbells over your chest with an overhand grip.","Bend the elbows, lowering the dumbbells toward the middle of your chest, elbows flared.","The dumbbell plates should nearly touch the chest, angling inward.","Press the dumbbells back up, extending the elbows and squeezing the triceps."],proTip:"Angling the dumbbells toward the chest isolates the medial head of the triceps.",targetMuscles:["Triceps (medial head)","Triceps (lateral head)"],primaryMuscle:"triceps",equipment:"Dumbbells"},"Dipy na maszynie (Assisted Dip Machine)":{steps:["Sit in the dip machine and grab the handles at your sides.","Set the load and brace your hands, keeping your torso upright.","Extend the elbows, pressing the handles down to full arm extension.","Return slowly, bending the elbows to a 90-degree angle."],proTip:"The machine lets you dial in the load safely and keep a fixed path.",targetMuscles:["Triceps","Lower chest","Front delts"],primaryMuscle:"triceps",equipment:"Dip Machine"},"Pompki diamentowe (Diamond Push-up)":{steps:["Assume a plank position with your hands close together under your chest.","Touch your thumbs and index fingers to form a diamond shape.","Lower your chest to your hands, keeping elbows close to the torso.","Press back up, extending the elbows and squeezing the triceps."],proTip:"The narrow hand position shifts emphasis from the chest to the triceps.",targetMuscles:["Triceps","Inner chest","Front delts"],primaryMuscle:"triceps",equipment:"Bodyweight"},"Dipy na ławce (Bench Dips)":{steps:["Sit on the edge of a bench and place your hands beside your hips.","Slide your hips off the bench, keeping legs straight or bent.","Lower your body by bending the elbows to a 90-degree angle.","Press back up by extending the elbows and squeezing the triceps."],proTip:"Keep your back close to the bench to protect the shoulders and load the triceps more.",targetMuscles:["Triceps","Front delts","Lower chest"],primaryMuscle:"triceps",equipment:"Bodyweight"},"Prostowanie ramion zza głowy z hantlą oburącz (Overhead DB Extension)":{steps:["Sit or stand tall holding a single dumbbell overhead with both hands.","Cup the top plate of the dumbbell with both palms, arms straight up.","Lower the dumbbell behind your head, bending the elbows and keeping them close.","Press the dumbbell back up to full extension, squeezing the triceps."],proTip:"Keep the elbows narrow and still to fully stretch the long head.",targetMuscles:["Triceps (long head)","Triceps (medial head)"],primaryMuscle:"triceps",equipment:"Dumbbell"},"Uginanie nadgarstków ze sztangą (Wrist Curl)":{steps:["Sit down and rest your forearms on your thighs, palms facing up.","Hold the barbell with an underhand grip, letting it roll to your fingertips.","Curl your wrists upward, lifting the bar through a full range.","Squeeze the forearms at the top and lower slowly."],proTip:"Let the bar roll to your fingertips at the bottom for full range of motion.",targetMuscles:["Wrist flexors","Forearm flexors"],primaryMuscle:"forearms",equipment:"Barbell"},"Odwrotne uginanie nadgarstków ze sztangą (Reverse Wrist Curl)":{steps:["Sit down and rest your forearms on your thighs, palms facing down.","Hold the barbell with a shoulder-width overhand grip.","Raise the backs of your hands upward, extending the wrists through full range.","Squeeze the extensors at the top and lower slowly."],proTip:"Use a light weight, as the wrist extensors are weaker than the flexors.",targetMuscles:["Wrist extensors","Forearm extensors"],primaryMuscle:"forearms",equipment:"Barbell"},"Izometryczny chwyt farmera (Farmer's Hold)":{steps:["Grab heavy dumbbells at your sides and stand tall.","Keep your chest up, shoulders pulled back and back straight.","Maintain a strong grip and a static position for the prescribed time.","Set the dumbbells down under control once time is up."],proTip:"The static hold builds crushing grip strength and forearm endurance.",targetMuscles:["Forearm flexors","Grip muscles","Trapezius"],primaryMuscle:"forearms",equipment:"Dumbbells"},"Uginanie hammer na wyciągu z liną (Cable Rope Hammer Curl)":{steps:["Attach a rope to the low pulley and grab both ends with a neutral grip.","Stand tall with elbows pinned to your torso.","Curl the elbows, bringing the rope up with a neutral (hammer) grip.","Squeeze at the top and return slowly to full extension."],proTip:"The hammer grip on the cable strongly works the brachioradialis and arm thickness.",targetMuscles:["Brachioradialis","Biceps","Brachialis"],primaryMuscle:"biceps",equipment:"Cable Machine"},"Wyciskanie wąsko w maszynie Smitha (Smith Close-Grip Press)":{steps:["Lie on a bench positioned under the Smith machine bar.","Grip the bar narrow, at shoulder width, and unrack the safeties.","Lower the bar to your lower chest, keeping elbows close to your body.","Press the bar back up to full extension, squeezing the triceps."],proTip:"The Smith machine's fixed path stabilizes the movement so you can focus on the triceps.",targetMuscles:["Triceps","Inner chest","Front delts"],primaryMuscle:"triceps",equipment:"Smith Machine"},"Brzuszki klasyczne (Crunch)":{steps:["Lie on your back, bend your knees, feet flat on the floor.","Cross your hands on your chest or place them by your temples (don't pull your neck).","Lift your shoulder blades, curling your torso toward your knees and contracting the abs.","Slowly lower your shoulder blades to the floor while keeping tension."],proTip:"Focus on curling the spine, not lifting your entire back.",targetMuscles:["Rectus abdominis","Obliques"],primaryMuscle:"core",equipment:"Bodyweight"},"Pełne spięcie brzucha (Sit-up)":{steps:["Lie on your back with knees bent, feet anchored.","Place your hands by your temples or crossed on your chest.","Lift your entire torso to a seated position, contracting the abs.","Lower your back to the floor under control."],proTip:"Don't jerk; control the lowering phase for more effect.",targetMuscles:["Rectus abdominis","Hip flexors"],primaryMuscle:"core",equipment:"Bodyweight"},"Brzuszki rowerek (Bicycle Crunch)":{steps:["Lie on your back, hands by your temples, legs raised.","Bring your right elbow to your left knee while extending the right leg.","Switch sides: left elbow to right knee, alternating like pedaling a bike.","Keep your lower back pressed to the floor throughout the movement."],proTip:"Rotate from the abs, don't pull your head with the elbows.",targetMuscles:["Rectus abdominis","Obliques"],primaryMuscle:"core",equipment:"Bodyweight"},"Plank boczny (Side Plank)":{steps:["Lie on your side, prop yourself on your forearm under the shoulder.","Stack your feet on top of each other and brace your abs.","Lift your hips, forming a straight line from head to feet.","Hold for the set time, then switch sides."],proTip:"Don't let your hips sag; keep one straight body line.",targetMuscles:["Obliques","Quadratus lumborum","Transverse abdominis"],primaryMuscle:"core",equipment:"Bodyweight"},"Hollow Rock (Bujanie w łódce)":{steps:["Lie on your back, arms extended overhead, legs straight.","Lift your shoulder blades and legs, forming a hollow boat shape.","Keeping the abs braced, rock rhythmically forward and back.","Don't let your lower back break out of the line of motion."],proTip:"The lower your legs, the harder it is, scale to your level.",targetMuscles:["Rectus abdominis","Transverse abdominis","Hip flexors"],primaryMuscle:"core",equipment:"Bodyweight"},"V-up (Scyzoryk)":{steps:["Lie on your back, arms extended overhead, legs straight.","Simultaneously lift your torso and straight legs into a V shape.","Reach your hands toward your feet at the top.","Lower torso and legs under control without touching the floor."],proTip:"Keep legs straight; bending the knees makes it easier.",targetMuscles:["Rectus abdominis","Hip flexors"],primaryMuscle:"core",equipment:"Bodyweight"},"Nogi do drążka (Toes to Bar)":{steps:["Hang from the bar with an overhand grip, arms extended.","Brace the abs and lift your straight legs toward the bar.","Touch your toes to the bar between your hands.","Lower the legs under control, avoiding uncontrolled swinging."],proTip:"Engage the lats to stabilize the hang and limit swinging.",targetMuscles:["Rectus abdominis","Hip flexors","Latissimus dorsi"],primaryMuscle:"core",equipment:"Pull-up bar"},"Unoszenie kolan w zwisie":{steps:["Hang from the bar with an overhand grip, arms extended.","Brace the abs to stabilize the body and limit swinging.","Pull your knees toward your chest, curling the pelvis.","Slowly lower your legs back to the starting position."],proTip:"At the top, curl the pelvis upward to engage the abs harder.",targetMuscles:["Rectus abdominis","Hip flexors"],primaryMuscle:"core",equipment:"Pull-up bar"},"Wyciskanie kółka do brzucha z klęku jednorącz":{steps:["Kneel and grip the wheel with one hand in front of you.","Brace your abs and roll the wheel forward, extending the torso.","Stop before losing tension, holding your hips steady against gravity.","Pull the wheel back by contracting the abs; switch hands after the set."],proTip:"The single-arm version heavily loads the obliques, start with a short range.",targetMuscles:["Rectus abdominis","Transverse abdominis","Obliques"],primaryMuscle:"core",equipment:"Ab wheel"},"Spięcia brzucha na ławce skośnej (Decline Sit-up)":{steps:["Hook your feet under the rollers of a decline bench, head down.","Cross your hands on your chest or place them by your temples.","Lift your torso by contracting the abs until you reach a seated position.","Lower your back under control without fully resting at the bottom."],proTip:"The steeper the decline, the harder it is, match the angle to your ab strength.",targetMuscles:["Rectus abdominis","Hip flexors"],primaryMuscle:"core",equipment:"Decline bench"},"Modlitewnik klęczący jednostronny (Cable Crunch)":{steps:["Set a rope on the high pulley and kneel sideways to the stack.","Grab the rope with both hands and bring it next to one shoulder.","Curl the torso down and toward the opposite hip, contracting the obliques.","Slowly return to the start, switch sides after the set."],proTip:"The side version emphasizes the obliques, drive the elbow to the opposite knee.",targetMuscles:["Rectus abdominis","Obliques"],primaryMuscle:"core",equipment:"Cable machine"},"Wysoki Woodchopper na wyciągu (z dołu do góry)":{steps:["Set the handle at the lowest pulley position and stand sideways.","Grab the handle with both hands at the hip farther from the stack.","Pull diagonally up over the opposite shoulder, rotating the torso.","Return to the start under control, switch sides after the set."],proTip:"Generate force from hip and core rotation, not just the arms.",targetMuscles:["Obliques","Transverse abdominis","Deltoids"],primaryMuscle:"core",equipment:"Cable machine"},"Dead Bug z hantlami (obciążony)":{steps:["Lie on your back, arms with dumbbells extended over your chest.","Raise your legs, knees and hips bent at right angles.","Simultaneously lower the opposite arm and leg toward the floor.","Return to center and repeat on the other side, lower back pressed to the floor."],proTip:"Dumbbells increase the anti-extension challenge, move slowly and with control.",targetMuscles:["Transverse abdominis","Rectus abdominis","Hip flexors"],primaryMuscle:"core",equipment:"Dumbbells"},"Pallof Press w przysiadzie (warianty)":{steps:["Set the cable handle at chest height and stand sideways to the stack.","Grab the handle with both hands at your chest and assume a half-squat.","Extend your arms straight out, resisting the rotation pulled by the cable.","Hold for a second, return to your chest, switch sides after the set."],proTip:"The half-squat engages the glutes and creates a stable anti-rotation base.",targetMuscles:["Obliques","Transverse abdominis","Glutes"],primaryMuscle:"core",equipment:"Cable machine"},"Dragon Flag (Flaga Smoka)":{steps:["Lie on a bench and grab it with both hands behind your head for stability.","Brace your whole body and lift it nearly vertical, resting on your shoulder blades.","Slowly lower your straight body as one rigid line.","Stop just above the bench and rise back up without touching it with your hips."],proTip:"Keep your body rigid like a plank, the lowering phase is the hardest.",targetMuscles:["Rectus abdominis","Transverse abdominis","Latissimus dorsi"],primaryMuscle:"core",equipment:"Bench"},"L-sit (Podpór kątowy)":{steps:["Grip the parallel bars and press up onto straight arms.","Brace the abs and lift your straight legs to horizontal, forming an L.","Hold the position, depressing the shoulder blades and bracing the whole body.","Lower the legs after the set time and rest."],proTip:"If you can't keep legs straight, start with bent knees (tuck L-sit).",targetMuscles:["Rectus abdominis","Hip flexors","Triceps"],primaryMuscle:"core",equipment:"Parallel bars"},"Plank z dotykaniem barków":{steps:["Get into a high plank on straight arms, feet shoulder-width apart.","Brace your abs and glutes, keeping the hips steady.","Lift one hand and tap the opposite shoulder without rotating the hips.","Return the hand to the floor and repeat, alternating sides."],proTip:"The wider your feet, the easier it is to stabilize the hips during the tap.",targetMuscles:["Transverse abdominis","Obliques","Deltoids"],primaryMuscle:"core",equipment:"Bodyweight"},"Superman (Unoszenie tułowia leżąc na brzuchu)":{steps:["Lie face down, arms extended in front, legs straight.","Contract your glutes and lower back, lifting arms and legs at the same time.","Pause at the top, squeezing the back muscles.","Slowly lower your arms and legs to the floor."],proTip:"This balances the abs by strengthening the posterior-chain stabilizers.",targetMuscles:["Erector spinae","Glutes","Quadratus lumborum"],primaryMuscle:"core",equipment:"Bodyweight"},Burpees:{steps:["From standing, squat down and place your hands on the floor.","Explosively kick your legs back into a plank position.","Do a push-up (or just touch your chest to the floor), then jump your feet back under your torso.","Jump up explosively with arms overhead and land softly."],proTip:"Keep your core braced throughout the plank phase to protect your lower back.",targetMuscles:["Full body","Abs","Chest","Legs"],primaryMuscle:"fullbody",equipment:"Bodyweight"},"Wspięcia na palce na prasie nożnej (Leg Press)":{steps:["Sit in the leg press and place the balls of your feet on the lower edge of the platform, heels off.","Extend your legs (knees slightly bent) and release the safety stops.","Lower your heels as far as possible to stretch the calves.","Push the platform with your toes, fully extending the ankles.","Hold the top for a second and return under control."],proTip:"Keep knees slightly bent and motionless so the movement comes only from the ankle joint.",targetMuscles:["Gastrocnemius","Soleus"],primaryMuscle:"calves",equipment:"Leg Press Machine"},"Wspięcia na palce w maszynie Smitha (stojąc)":{steps:["Set the Smith bar at shoulder height and place a small platform under the balls of your feet.","Step under the bar, rest it on your traps and unrack it.","Lower your heels below the platform level to stretch the calves.","Rise as high as possible onto your toes, squeezing the calves.","Return slowly to a full stretch."],proTip:"The Smith bar guides the path vertically, so focus on maximum rise and full stretch without balancing.",targetMuscles:["Gastrocnemius","Soleus"],primaryMuscle:"calves",equipment:"Smith Machine"},"Wspięcia na palce jednonóż z hantlą":{steps:["Hold a dumbbell in one hand and grab a stable support with the other for balance.","Place the ball of one foot on a platform (plate or step), the other foot lifted.","Lower the heel of the working leg below the platform level.","Rise as high as possible onto the toes of that single leg.","Complete the reps and switch sides."],proTip:"Unilateral work corrects strength imbalances between calves and increases range of motion.",targetMuscles:["Gastrocnemius","Soleus"],primaryMuscle:"calves",equipment:"Dumbbell"},"Wspięcia na palce ze sztangą stojąc":{steps:["Place a barbell on your traps like for a squat and put a plate under the balls of your feet.","Stand tall, brace your core and keep your back straight.","Lower your heels below the plate level to stretch the calves.","Rise onto your toes as high as possible, squeezing the calves at the top.","Lower under control to a full stretch."],proTip:"Without a guide you must actively stabilize the torso, so choose a weight that lets you stay balanced.",targetMuscles:["Gastrocnemius","Soleus"],primaryMuscle:"calves",equipment:"Barbell"},"Wspięcia na palce jednonóż na podwyższeniu (masa ciała)":{steps:["Stand with the ball of one foot on the edge of a step, heel off the edge.","Hook the other foot behind the working leg's ankle, place a hand on a wall for balance.","Lower the heel below the step edge to a full stretch.","Rise as high as possible onto the toes of that single leg.","Complete the reps and switch legs."],proTip:"Great as a warm-up or finisher because it gives a large range without external load.",targetMuscles:["Gastrocnemius","Soleus"],primaryMuscle:"calves",equipment:"Bodyweight"},"Wznosy palców na piszczel (Tibialis Raise)":{steps:["Lean your back and glutes against a wall, heels about 15-30 cm away from it.","Keep your legs straight and feet flat on the floor.","Lift your toes and forefoot as high as possible toward the shins, heels staying down.","Hold the contraction at the top for a second.","Lower the feet slowly to a full stretch of the front of the shin."],proTip:"Training the antagonist of the calf improves ankle balance and reduces shin splint risk.",targetMuscles:["Tibialis anterior","Toe extensors"],primaryMuscle:"calves",equipment:"Bodyweight"},"Skakanka jako trening łydek":{steps:["Grab the rope, elbows close to the torso, feet together.","Turn the rope with your wrists and bounce low off the balls of your feet.","Land softly on the toes, absorbing through the calves and ankles.","Keep an even rhythm and springy ankle action throughout the set duration."],proTip:"Jump low and soft off the balls of your feet to maximally engage the calves and spare the knees.",targetMuscles:["Gastrocnemius","Soleus","Tibialis anterior"],primaryMuscle:"calves",equipment:"Jump Rope"},"Wspięcia na palce z kettlebell stojąc":{steps:["Hold a kettlebell with both hands in front of you, or one in each hand at your sides.","Stand with the balls of your feet on a plate or step, heels off.","Lower your heels below the platform level to stretch the calves.","Rise as high as possible onto your toes, squeezing the calves at the top.","Lower under control to a full stretch."],proTip:"Holding the kettlebell low lowers your center of gravity and makes balance easier through a big range.",targetMuscles:["Gastrocnemius","Soleus"],primaryMuscle:"calves",equipment:"Kettlebell"},"Wspięcia na palce na hack squacie":{steps:["Set up in the hack squat machine with your back against the pad, shoulders under the cushions.","Place the balls of your feet on the lower edge of the platform, heels off, extend the legs and unrack.","Lower your heels as far down as possible to stretch the calves.","Push the weight with your toes, fully extending the ankles.","Hold the top and return under control."],proTip:"The fixed back angle of the hack squat isolates the calves without needing to stabilize the torso.",targetMuscles:["Gastrocnemius","Soleus"],primaryMuscle:"calves",equipment:"Hack Squat Machine"},"Wspięcia na palce na suwnicy siedząc (zgięte kolana)":{steps:["Place a bench under the Smith bar and sit down, balls of feet on a plate in front of you.","Rest the bar on your thighs just above the knees with a towel for comfort, then unrack.","Lower your heels below the plate level to stretch the calves.","Raise your heels as high as possible, squeezing the soleus at the top.","Lower under control to a full stretch."],proTip:"The bent knee deactivates the gastrocnemius and shifts work to the soleus, key for calf thickness.",targetMuscles:["Soleus","Gastrocnemius"],primaryMuscle:"calves",equipment:"Smith Machine"}};export{e as exerciseDetailsEn};
